	--self._isPbData = isPbData

	---@type LFightObjectCtrl
	self._objCtrl = LFightObjectCtrl:New(self)
	self._effCtrl = LFightEffectCtrl:New(self)
	self._logCtrl = LFightLogCtrl:New(self)
	self._treaObjCtrl = LTreasureObjCtrl:New(self)

	---@type LFightBuffExpreCtrl
