--- 战斗流程控制
------------------------------------------------------------------
function LFightUnit:StartRun()
	self:StopRun()
	self._loopTimer = LxTimer.LoopTimeCall(function()
		self:OnRun()
	end,0,false,-1)
end

function LFightUnit:StopRun()

	--printInfoN("stop battle loop")
	LxTimer.LoopTimeStop(self._loopTimer)
	self._loopTimer  = nil

	if self._delatBackToBattleHandle then
		LxTimer.DelayTimeStop(self._delatBackToBattleHandle)
		self._delatBackToBattleHandle = nil
	end
end

function LFightUnit:OnRun()
	if self._isToFront then
		return
	end

	local time = self:GetTime()
	--printInfoN("cur time "..time)
	--self._currentTime = time
	local noPosBuff = true

	self:UpdateChase(time)

	if not self._isBackgroundPlay then

		while(self:IsOfflineRound())  do
			self:CheckNextPlay()
		end

		if self._curSkill and #self._curSkill > 0 then
			local indexList = {}
			for i, v in ipairs(self._curSkill) do
				if not v:OnRun(time) then
					--- 技能同组表现，再最后一组隐藏血条
					v:NeedResetBlock(#self._curSkill == 1)
					v:ResetHerosBgState()
					v:Destroy()
					table.insert(indexList,i)
				end
			end
			for i=#indexList, 1, -1 do
				table.remove(self._curSkill,indexList[i])
			end
		end
		self._objCtrl:OnRun(time)
		self._effCtrl:OnRun(time)
		--self:UpdateTeamHp(time)
		self:UpdateHurtCount(time)
		self:OnObjRoundUpdate()

		self._buffExpreCtrl:OnRun(time)

		noPosBuff = self:OnBuffPositionRun(time)

		if self._bWaitBattleStart and self._waitStartTime <= time then
			self:StartBattlePlay()
		end
	end

	local cnt = 1
	if self._curRoundIndex == 1 then
		cnt = 10
	end

	--printInfoN("battle loop ------------1")

	while(cnt>0) do
		local isSkillEnd = not self._curSkill or #self._curSkill == 0
		--printInfoN("battle loop isSkillEnd "..tostring(isSkillEnd))
		local isBuffEnd = self._buffExpreCtrl:IsNoBuff()
		--printInfoN("battle loop isBuffEnd "..tostring(isBuffEnd))
		if isSkillEnd and isBuffEnd and noPosBuff then


			local needWait = self:WaitDeadShow()
			local waitDeadAction = self:CheckWaitDeadAction()
			--printInfoN("battle loop needWait "..tostring(needWait))
			--printInfoN("battle loop _waitNextSkillShow "..tostring(self._waitNextSkillShow))
			if self._waitNextSkillShow and self._waitTime <= time and not needWait and not waitDeadAction then

				--local timeCostSingle = time - (self._lastTime or 0)
				--printErrorN(string.format("------battle loop timeCostSingle %s ,isBack %s",timeCostSingle,self._isBackgroundPlay))
                --
				--self._lastTime = time
				self:SetWaitNextSkillShow(false)
				self:CheckNextPlay()
				--printInfoN("battle loop ------------2")
			end
		end
		cnt = cnt -1
	end
	--技能表演完次可以下一个

	if self._isTransmit then
		if self._logCtrl:IsLogOpen() then
			self._logCtrl:LogError("istransmit")
		end
		return
	end


	if self._isBattleEnd and not self._isEndExecute and not self._isShowingLastEff then
		local isAllDeadEnd  = self._objCtrl:IsAllDeadTweenEnd()
		self._isWaitAllDead = not isAllDeadEnd
		if isAllDeadEnd then
			self:OnBattleEnd()
		end
	end
end

function LFightUnit:WaitDeadShow()
	local objList = self._objCtrl:GetObjectList()
	for k,v in pairs(objList) do
		if v:HasDeadShowList() then
			return true
		end
	end

	return false
end

function LFightUnit:IsOfflineRound()
	if self._offlineRount>0 and self._offlineRount>= self._curRoundIndex then
		return true
	end
	if self._isBattleEnd then
		return false
	end

	return false
end


function LFightUnit:SetWaitNextSkillShow(bool)
	--if LOG_INFO_ENABLED then
	--	print("LFightUnit:SetWaitNextSkillShow(bool) "..tostring(bool))
	--end
	self._waitNextSkillShow = bool
end
--预备下一个播放,主要是预加载技能特效
function LFightUnit:PreloadRoundPlay(roundIndex, boutIndex, actionIndex)
	local preloadSkill = self._preloadSkill
	if preloadSkill then
		local state = self:GetPreloadState(preloadSkill,roundIndex, boutIndex, actionIndex)
		if state == 1 then
			self:ClearPreloadSkill()
		elseif state == 2 or state == 3 then
			return
		end
	end

	self._isLastAtk = false

	if roundIndex > self._totalRoundIndex  or self._isBackgroundPlay then
		self._isLastAtk = true
		return
	end

	local roundDataList = self._battleReportData:GetRoundDataList()
	local roundData = roundDataList[roundIndex]
	-- try get bout
	local boutData = roundData and roundData:GetBoutDataByIndex(boutIndex) or nil
	if boutData == nil then
		self:PreloadRoundPlay(roundIndex + 1, 1, 1)
		return
	end

	-- try get action
	local actionDataList = boutData and boutData:GetActionDataByIndex(actionIndex) or {}
	if #actionDataList == 0 then
		self:PreloadRoundPlay(roundIndex, boutIndex + 1, 1)
		return
	end


	local recordSpMap = {}
	-- reload action bt actionData
	local index = 1
	local list = {}
	---@param actionData LFightBoutActionData
	for i, actionData in ipairs(actionDataList) do
		local aId = actionData:GetAttackId()
		local skillRefId = actionData:GetSkill()
		local expressionRefId = actionData:GetExpress()

		local heroData = self:GetHeroData(aId)
		local hurtCount = self:GetHurtCountFromActionData(actionData)
		local atkHero = self:GetHero(aId)
		local isChangeSpine = false
		if atkHero and not atkHero:IsDead() then
			isChangeSpine = atkHero:GetChangeSpineState()
		end
		local skillData
		if heroData then
			local isCreateSkillData = false
			if isChangeSpine then
				--- 变身下，直接从皮肤拿表现
				local expressionId = gModelSkill:GetSkinExpress(atkHero:GetSkinId(),expressionRefId,true)
				if expressionId and expressionId > 0 then
					skillData = heroData:GetSkillTransformData(skillRefId,expressionId,expressionRefId) or nil
					isCreateSkillData = skillData ~= nil
					if isCreateSkillData then
						---@type LFightSkill
						local skill = LFightSkill:New(self,skillData,atkHero,actionData)
						skill:PreloadPlayList()
						list[index] = skill
						index = index + 1
					end
					skillData = nil
				end
			end
			if not isCreateSkillData then
				local battleObjType = heroData:GetArtifactType()
				if battleObjType == LFightConst.OBJ_DIVINEWEAPON then
					--if skillRefId == 510421 or skillRefId == 510311 then
					--	skillRefId = 860311
					--	expressionRefId = 3401603
					--end
					skillData = heroData:GetSkillData(skillRefId,expressionRefId,hurtCount) or nil
				else
					skillData = heroData:GetSkillData(skillRefId,expressionRefId,hurtCount) or nil
					if not skillData then
						local skinTempRefId = actionData:CheckPassiveSkillHasShow()
						if skinTempRefId and skinTempRefId > 0 then
							skillData = heroData:GetSkillData(skillRefId,skinTempRefId,hurtCount,0) or nil
						end
					end
				end
			end
		end
		if skillData and atkHero then
			---@type LFightSkill
			local skill = LFightSkill:New(self,skillData,atkHero,actionData)
			skill:PreloadPlayList()
			list[index] = skill
			index = index + 1
		end
	end

	if table.keysize(list) == 0 then
		self:PreloadRoundPlay(roundIndex,boutIndex,actionIndex + 1)
		return
	end

	local data = {
		round = roundIndex,
		bout = boutIndex,
		action = actionIndex,
		skillList = list
	}

	self._preloadSkill = data

end

---state 1 passed,2 current ,3 future
function LFightUnit:GetPreloadState(preloadSkill,roundIndex,boutIndex,actionIndex)
	local state = nil
	if roundIndex < preloadSkill.round then
		state = 3
	elseif roundIndex == preloadSkill.round then
		if boutIndex < preloadSkill.bout then
			state = 3
		elseif boutIndex == preloadSkill.bout then
			if actionIndex < preloadSkill.action then
				state = 3
			elseif actionIndex == preloadSkill.action then
				state = 2
			else
				state = 1
			end
		else
			state = 1
		end
	else
		state = 1
	end

	return state
end

function LFightUnit:GetFirstSkillData()
	local roundDataList = self._battleReportData:GetRoundDataList()
	local maxRound = self._battleReportData:GetTotalRound()
	local initR = self._curRoundIndex
	local initB = self._curBout
	local initA = self._curAction+1
	for round = initR,maxRound do
		local roundData = roundDataList[round]
		local maxBout = roundData:GetTotalBout()
		for bout = initB, maxBout do
			local boutData = roundData:GetBoutDataByIndex(bout)
			local maxAction = boutData:GetTotalAction()
			for action = initA ,maxAction do
				local actionDataList = boutData:GetActionDataByIndex(action)
				for k,v in ipairs(actionDataList) do
					local aId = v:GetAttackId()
					local skillRefId = v:GetSkill()
					local expressionRefId = v:GetExpress()

					local heroData = self:GetHeroData(aId)
					local hurtCount = self:GetHurtCountFromActionData(v)
					local atkHero = self:GetHero(aId)
					local skillData = heroData and heroData:GetSkillData(skillRefId,expressionRefId,hurtCount) or nil
					if skillData and atkHero then
						return skillData,atkHero
					end
				end
			end
		end
	end
end

function LFightUnit:PreloadFirstSkillEff()
	self._effectNeedPreLoadLen = 0
	self._effectPreloadLen = 0

	local skillData,atkHero= self:GetFirstSkillData()
	if not skillData then
		self:OnEffectPreloaded()
		return
	end

	local effList = skillData:GetPlayEffList()

	local treaEff = nil
	local effDataList = {}
	for k,v in ipairs(effList) do
		local effType = v.effType
		if LSkillEffConst.PRELOAD_EFFECT_MAP[effType] then
			table.insert(effDataList,v)
		elseif effType == LSkillEffConst.PLAY_EFF_TREASURE then
			treaEff = v
		end
	end

	if #effDataList>0 then
		local effTask =
		{
			effList = effDataList,
			endFunc = function() self:OnEffectPreloaded() end,
		}

		self._effectNeedPreLoadLen = self._effectNeedPreLoadLen + 1
		local effectCtrl = self:GetEffectCtrl()
		effectCtrl:PreloadEffList(effTask,atkHero)
	end

	if treaEff then
		local heroId = atkHero:GetId()
		self._effectNeedPreLoadLen = self._effectNeedPreLoadLen + 1
		if self._treaObjCtrl then
			self._treaObjCtrl:LoadObj(heroId,treaEff,function ()
				self:OnEffectPreloaded()
			end)
		end
	end


	if self._effectNeedPreLoadLen== 0 then
		self:OnEffectPreloaded()
	end
end

function LFightUnit:OnEffectPreloaded()
	self._effectPreloadLen = self._effectPreloadLen + 1
	if self._effectPreloadLen < self._effectNeedPreLoadLen then
		return
	end
	self._firstEffLoaded = true
	self:OnRequirePreloadReady()
end


---战斗循环执行
function LFightUnit:CheckNextPlay()
	if self._curRoundIndex <= self._totalRoundIndex then
		self:TryPlayNext()
	end

	if self._isPlayAllFinished and not self._isBattleEnd then
		self._isBattleEnd = true

		self:StopChase()
		--self:OnBattleEnd()--战斗结束
	end
end
