function LFightUnit:AttachMapTrans(mapTrans)
	self._mapTrans = mapTrans

	self._isTransmit = false
end

---回复战斗到前台
function LFightUnit:ResumeBattleToFront()

	if CS.IsWebGL() then
		--LResRelease.WebglRelease()
		LxResUtil.RunUnusedAssetUnload()
	end	
		

	self._isToFront = false
	--printInfoN("-------------------------resume battle ")
	--self:InitSpeed()
	self:ChangeToActive()
	self:LoadGridPos()
	self:ResetStartPlayTime()
	self:LoadHero()

	self:ShowWaitStartEff()

end

function LFightUnit:InitBattle()

	self._startTimestamp = os.time()


	self._bBattleInit = true
	self._curRoundIndex = 1

	self:InitSpeed()
	self:InitFormationData()

	self:InitPlayRoundData()
	self:CalcOfflineRoundCount()
	if not self._isBackgroundPlay then
		gLFightManager:ResetTimeScale()
	end
	self:StartRun()

end

---开始前台战斗,加载完英雄之后播放出生动画后开始战斗
function LFightUnit:StartFrontBattle()

	--gLFightManager:RecordBattleBackState(self._reportId,false)
	if CS.IsWebGL() then
		--LResRelease.WebglRelease()
		LxResUtil.RunUnusedAssetUnload()
	end

	self:InitShowHurtCnt()
	self:InitBattle()
	self:LoadGridPos()
	self:ResetStartPlayTime()
	self:LoadHero()
	self:PreloadRoundPlay(self._curRoundIndex, 1, 1)

	self:ShowWaitStartEff()
end

