------------------------------------------------------------------
--- 加载格子位置
---mapTrans   rootTrans
------------------------------------------------------------------
function LFightUnit:LoadGridPos()
	local mapTrans = self._mapTrans
	local layerRootTrans = CS.FindTrans(mapTrans, "LayerRoot")
	self._effectRootTrans = CS.FindTrans(layerRootTrans, "LayerEffect")
	self._objectRootTrans = CS.FindTrans(layerRootTrans, "LayerObject")
	self._fadeRoot= CS.FindTrans(layerRootTrans, "LayerBg/Bg")

	---@type LFormationGrid
	local formationGrid = gLFightManager:GetFormationGrid()

	local gridA, gridB, mapCorePos = formationGrid:GetTeamPosData()

	self._mapCorePoint = mapCorePos:Clone()


	---格子必须按照顺序放九个
	local formationGridA = {}
	for k,v in pairs(gridA) do
		formationGridA[k] = v:Clone()
	end

	local formationGridB = {}
	for k,v in pairs(gridB) do
		formationGridB[k] = v:Clone()
	end

	self._formationCenterPositionA = formationGrid:GetCenterAPosition()
	self._formationFrontCenterPositionA = formationGridA[2]
	self._formationCenterPositionB = formationGrid:GetCenterBPosition()
	self._formationFrontCenterPositionB = formationGridB[2]

	self._mapFormationGridA = formationGridA
	self._mapFormationGridB = formationGridB
end

function LFightUnit:GetFadeRoot()
	return self._fadeRoot
end

function LFightUnit:GetRowCenterPos(side,targetGrid)
    local grids = side == LFightConst.SIDE_TEAM_A and self._mapFormationGridA or self._mapFormationGridB
    local gridIndex = Mathf.Clamp(targetGrid,1,9)
    local centerIndex =  math.floor((gridIndex - 1) / 3) * 3 + 2
    local pos = grids[centerIndex]:Clone()

    return pos
end

