function LFightUnit:OnLoadHeroEnd()
	self._nowHeorLoadedLen = self._nowHeorLoadedLen + 1
	--printInfoN(string.format("now len %s ,total len %s ",self._nowHeorLoadedLen,self._totalHeroLen))
	if(self._nowHeorLoadedLen >= self._totalHeroLen) then

		self._allHeroLoaded = true
		self:OnRequirePreloadReady()
	end
end

function LFightUnit:OnRequirePreloadReady()
	if not self._firstEffLoaded then
		--printInfoN(string.format("not self._firstEffLoaded"))
		return
	end
	if not self._allHeroLoaded then
		return
	end

	self._bWaitBattleStart = true
	--printErrorN("zhuanchang preload finished .....")
end

function LFightUnit:ResetStartPlayTime()
	self._waitStartTime = self:GetTime() + 1.3
end

function LFightUnit:StartBattlePlay()
	self._bWaitBattleStart = false
	self._isStartPlay = true
	FireEvent(EventNames.PLAY_START_BATTLE_EFFECT)
	--FireEvent(EventNames.WAIT_ZHUANCHANGE_END)
	----重回战斗不播放出生动画
	if self._isBackToBattle then
		self:PreparePlay()
	else
		self:PlayBirth()
	end
end

function LFightUnit:IsStartPlay()
	return self._isStartPlay
end
------------------------------------------------------------------
--- 播放所有Hero进场动画，播放完毕进入战斗
------------------------------------------------------------------
---准备开始播放战斗
function LFightUnit:PreparePlay()
	self:HideWaitEff()

	local objCtrl = self:GetObjectCtrl()
	local objList = objCtrl:GetObjectList()

	--显示血条
	for k,v in ipairs(objList) do
		if not v:IsDead() then
			v:ReleaseHideKey("dead")
			v:ShowDisplayObject(true)

			v:SetHeroBgVisiable(true)
		end
		v:RefreshAllBuffEffect()
		v:UpdateCanReliveEff()
		v:SetPosByGrid()
	end

	if self._isBattleEnd then
		self:OnBattleEnd()
	else
		self._isBattleStart = true
		self:SetSpeed(self._speed)

		--开始战斗
		if self._isBackToBattle then
			if self._bBattleInit then
				self:PreloadRoundPlay(self._curRoundIndex, self._curBout, self._curAction+1)
			end
			if self._delatBackToBattleHandle then
				LxTimer.DelayTimeStop(self._delatBackToBattleHandle)
				self._delatBackToBattleHandle = nil
			end
			-- 重回战斗1秒钟后才开始播放，要做一些预加载和清理工作
			self._delatBackToBattleHandle = LxTimer.DelayTimeCall(function()
				self._delatBackToBattleHandle = nil
				self:CheckNextPlay()
			end, 1.2)
		else
			self:CheckNextPlay()
		end

	end

end

function LFightUnit:GetSpeed()
	if not self._speed then
		self:InitSpeed()
	end
	return self._speed
end

function LFightUnit:InitSpeed()
	local initSpeed = self._combatExtraData.initSpeed
	--self._speed = gModelBattle:GetBattleSpeed(self._combatType,initSpeed)
	self._speed = gModelBattle:GetUnitBattleSpeed(self._combatType,initSpeed)

end

function LFightUnit:SetSpeed(speed)
	self._speed = speed

	if not self._isBattleStart then
		return
	end

	if self._isBackgroundPlay then
		return
	end

	gLFightManager:PlayBattleTimeScale(self._speed)

	if CS.IsUnityEdit() then
		local gmSpeed = gModelBattle:GetGMSpeed()
		if gmSpeed and gmSpeed>0 then
			gLFightManager:PlayBattleTimeScale(gmSpeed)
		end
	end
end

function LFightUnit:SetBirthSpeed(speed)
	if speed and speed > 0 then
		gLFightManager:PlayBattleTimeScale(speed)
	end
end

function LFightUnit:ResetSpeed()

	if self._isBackgroundPlay then
		return
	end

	local speed = self:GetSpeed()
	if not self._isBattleStart then
		speed = 1
	end

	gLFightManager:PlayBattleTimeScale(self._speed)
end


---检测所有出生动画播放完毕
function LFightUnit:OnPlayBirthEnd()
	self._nowHeroBirthLen = self._nowHeroBirthLen + 1
	if(self._nowHeroBirthLen < self._totalHeroBirthLen) then return end
	self:PreparePlay()
end

function LFightUnit:PlayBirth()      ---检查修正   移动进场未完善
	--以所有在战场英雄最长的进场动画时间为准 （留个默认值，防止某些情况下获取不到数据）
	--printInfoN("LFightUnit:PlayBirth()  ")
	local objCtrl = self:GetObjectCtrl()
	local objList = objCtrl:GetObjectList()

	local endFunc = function()
		self:OnPlayBirthEnd()
	end



	self._nowHeroBirthLen = 0

	local totalBirth = 0
	for k,v in ipairs(objList) do
		if not v:IsDead() then
			totalBirth = totalBirth + 1
		end
	end
	self._totalHeroBirthLen = totalBirth

	for k,v in ipairs(objList) do
		if not v:IsDead() then
			v:ShowBirth(endFunc)
		end
	end
end


------------------------------------------------------------------
---
------------------------------------------------------------------
---切到下一回合
function LFightUnit:ChangeToNextRound()
	local curRound = self._curRoundIndex + 1
	if curRound > self._totalRoundIndex then
		self._isPlayAllFinished = true
		return false
	end
	self._curRoundIndex = curRound
	self:InitPlayRoundData(true)
end

---检测action和bout结束
function LFightUnit:CheckPlayData()
	local curRound = self._curRoundIndex

	if curRound > self._totalRoundIndex then
		self._isPlayAllFinished = true
		return false
	end

	local curAction = self._curAction
	local totalAction = self._curTotalAction

	--没有action数据的需要表演一次
	if curAction >= totalAction and curAction > 0  then
		--表演结束了 换到下一个出手数据
		local curBout = self._curBout
		curBout = curBout + 1
		self._curBout = curBout

		if curBout > self._curTotalBout then
			--回合结束了，换到下一个回合
			self:ChangeToNextRound()
		else
			local roundData = self._curRoundData
			--初始 出手数据,
			self._curAction = 0
			local boutData = roundData:GetBoutDataByIndex(curBout)
			self._curBoutData = boutData
			self._curTotalAction = boutData:GetTotalAction()
		end
	end
	return true
end

---初始当前回合数据
function LFightUnit:InitPlayRoundData(isChangeNext)

	self._playedHeros = {}

	local round = self._curRoundIndex

	local roundDataList = self._battleReportData:GetRoundDataList()
	local roundData = roundDataList[round]
	self._curRoundData = roundData


	self._curBout = 1

	local totalBout = roundData and roundData:GetTotalBout() or 0

	self._roundCount = roundData and roundData:GetRound() or 0

	self._curTotalBout = totalBout

	self._curAction = 0

	if totalBout == 0 then -- 本次回合没有出手数据
		self._curBoutData = nil
		self._curTotalAction = 0
	else
		local boutData = roundData:GetBoutDataByIndex(self._curBout)
		self._curBoutData = boutData
		self._curTotalAction = boutData:GetTotalAction()
	end

	local round = self._roundCount < 1 and 1 or self._roundCount --默认回合1
	self:OnRoundUpdate(round)
	--[[if isChangeNext then
		self:OnRoundOtherDivineUpdate(round)
	else
		self:OnRoundDivineUpdate(round)
	end]]
	if isChangeNext and self._curRoundIndex > 2 then
		--- 回合末才释放，需要等到下个回合才会变更
		self:OnRoundDivineUpdate(round)
	end

	if self._isBackgroundPlay then
		return
	end
	if self:IsOfflineRound() then
		return
	end

	FireEvent(EventNames.ROUND_UPDATE,true)

	local speedDataList = self:GetCurSpeedDataList()
	FireEvent(EventNames.ON_HERO_SPEED_LIST_UPDATE,speedDataList)

	if(LOG_INFO_ENABLED) then
		printInfoN("FireEvent(EventNames.ON_HERO_SPEED_LIST_UPDATE,speedDataList) ")
	end

	FireEvent(EventNames.ON_SKILL_LIST_UPDATE)
	FireEvent(EventNames.ON_DIVINE_SKILL_UPDATE)
end

function LFightUnit:GetCurSpeedDataList()
	local roundData = self._curRoundData
	if not roundData or roundData:GetRound() < 1 then
		local roundDataList = self._battleReportData:GetRoundDataList()
		roundData = roundDataList[2]
		if not roundData then
			return {}
		end
	end

	local speedList = roundData:GetSpeedList()
	if not speedList then
		return {}
	end
	local speedDataList = self:FormatSpeedDataList(speedList)
	return speedDataList
end

function LFightUnit:FormatSpeedDataList(speedList)
	local dataList = {}
	for k,v in ipairs(speedList) do
		local id = v.id
		if not self._playedHeros[id] then
			local heroData = self:GetHeroData(id)
			local itemdata =
			{
				id = id,
				refId = heroData:GetRefId(),
				isMon = heroData:IsMonster(),
				star = heroData:GetStar(),
				skin = heroData:GetSkinId(),
				form = heroData:GetForm(),
				isRight = heroData:GetActOn() == LFightConst.ACTON_TEAM_B,
				isDead = heroData:IsDead(),
				speed = v.speed,
				index = heroData:GetIndex(),
			}
			local quality = heroData:GetQuality()
			if quality and quality>0 then
				itemdata.quality = quality
			end

			table.insert(dataList,itemdata)
		end
	end

	table.sort(dataList,function (a,b)
		if a.speed ~=  b.speed then
			return a.speed>b.speed
		end

		if a.index ~= b.index then
			return a.index<b.index
		end

		local aPrio = a.isRight and 2 or 1
		local bPrio = b.isRight and 2 or 1
		return aPrio<bPrio
	end)

	return dataList
end

function LFightUnit:IsHeroPlayed(id)
	return self._playedHeros and self._playedHeros[id] or false
end

