--- 播放战斗表现
function LFightUnit:TryPlayNext()
	--local oldBout = self._curBout
	if not self:CheckPlayData(not self._isBackgroundPlay) then
		--等待下一次,本次没有表演
		self._waitTime = 0
		self:SetWaitNextSkillShow(true)
		return
	end

	if self._curTotalBout == 0 then --回合没有出手数据,下一回合
		self:ChangeToNextRound()

		--等待下一次,本次没有表演
		self._waitTime = 0
		self:SetWaitNextSkillShow(true)
		return
	end

	if self._isPlayAllFinished then
		return
	end

	self:CheckRemoveSummon()

	local curAction = self._curAction + 1
	self._curAction = curAction

	local totalAction = self._curTotalAction
	local boutData = self._curBoutData

	local ActionData = boutData:GetActionDataByIndex(curAction)
	if ActionData == nil then
		--local textesd = 1
		self._waitTime = 0
		self:SetWaitNextSkillShow(true)
		return
	end

	if not self._isBackgroundPlay then
		self:ClearHurtCntList()
		if not self._buffEffectIs92 then
			self._hurtCounter:EndCounter()
		end
		self._buffEffectIs92 = false
		--FireEvent(EventNames.BATTLE_HURT_COUNT_UPDATE,nil,0)
	end

	--if self._curBout ~= oldBout then
	local atkId = boutData:GetAttackId()
	local skillId = boutData:GetSkill()
	if skillId>0 then
		self._playedHeros[atkId] = true
		if not self._isBackgroundPlay then
			FireEvent(EventNames.ON_HERO_PLAY,atkId)
		end
	end
	--end

	local boutSkillShowMap = self._boutSkillShowMap
	if not boutSkillShowMap then
		boutSkillShowMap = {}
		self._boutSkillShowMap = boutSkillShowMap
	end

	local skillTime = 1
	local skillTimeInclu = 1
	local time = self:GetTime()
	local skillDataList = {}

	local atkSide = nil

	local hasChangeSpineState = false
	for i, actionData in ipairs(ActionData) do
		local aId = 0
		local skillRefId = 0
		local expressionRefId = 0
		if totalAction == 0 then --没有acion数据 ，用bout里面的攻击目标和技能
			aId = boutData:GetAttackId()
			skillRefId = boutData:GetSkill()
			--expressionRefId = boutData:GetExpress()
		else
			aId = actionData:GetAttackId()
			skillRefId = actionData:GetSkill()
			expressionRefId = actionData:GetExpress()
		end

		local heroData = self:GetHeroData(aId)


		---刷新神器回合显示
		--local atkObj = self._objCtrl:GetObjectById(aId)
		--if atkObj then
		--	local objType = atkObj:GetObjectType()
		--	if objType == LFightConst.OBJ_ARTIFACT then
		--		local isLeft = atkObj:GetSide() == LFightConst.SIDE_TEAM_A
		--		self:GenArtifactCd(isLeft)
		--	end
		--end

		---刷新宝物技能显示
		if heroData then
			local objType = heroData:GetArtifactType()
			if objType == LFightConst.OBJ_TREASURE then
				local isBack = self._isBackgroundPlay
				heroData:GenTreasureCd(skillRefId,not isBack)
			elseif objType == LFightConst.OBJ_DIVINEWEAPON then
				if self._isBackgroundPlay then
					heroData:GenDivineWeaponCd(skillRefId,true,true)
				end
			end
		end
		---更新数据模型
		self:UpdateHeroDataFromActionData(actionData)
		--printInfoN("UpdateHeroDataFromActionData ")
		local hurtCount = self:GetHurtCountFromActionData(actionData)
		--print("攻击次数：" .. hurtCount)
		self:UpdateHeroDataBuffData()

		local isIns = false
		local skillData = heroData and heroData:GetSkillData(skillRefId,expressionRefId,hurtCount)

		local atkHero = self:GetHero(aId)
		local isChangeSpine = false
		if atkHero and not atkHero:IsDead() then
			isChangeSpine = atkHero:GetChangeSpineState()
		end
		local isCreateSkillData = false
		if isChangeSpine then
			--- 变身下，直接从皮肤拿表现
			local expressionId = gModelSkill:GetSkinExpress(atkHero:GetSkinId(),expressionRefId,true)
			if expressionId and expressionId > 0 then
				isCreateSkillData = true
				skillData = heroData and heroData:GetSkillTransformData(skillRefId,expressionId,expressionRefId) or nil
				if skillData then
					local _skillTime,_skillTimeInclu = skillData:GetSkillShowTime()
					_skillTime = _skillTime or 0
					_skillTimeInclu = _skillTimeInclu or 0
					skillTime =  math.max(_skillTime, skillTime)
					isIns = true
					table.insert(skillDataList,{skillData = skillData,time = time,skillTime = skillTime,actionData = actionData,aId = aId})
				end
			end
			hasChangeSpineState = true
		end

		skillData = heroData and heroData:GetSkillData(skillRefId,expressionRefId,hurtCount) or nil
		if heroData and not skillData then
			local boutSkillShowData = boutSkillShowMap[self._curRoundIndex]
			if not boutSkillShowData then
				boutSkillShowData = {}
				boutSkillShowMap[self._curRoundIndex] = boutSkillShowData
			end
			local boutSkillAIdMap = boutSkillShowData[aId]
			if not boutSkillAIdMap then
				boutSkillAIdMap = {}
				boutSkillShowData[aId] = boutSkillAIdMap
			end
			local skinTempRefId = actionData:CheckPassiveSkillHasShow()
			if skinTempRefId and skinTempRefId > 0 and not boutSkillAIdMap[skinTempRefId] then
                boutSkillAIdMap[skinTempRefId] = true
				skillData = heroData:GetSkillData(skillRefId,skinTempRefId,hurtCount,0) or nil
			end
		end

		if skillData then
			local _skillTime,_skillTimeInclu = skillData:GetSkillShowTime()
			_skillTime = _skillTime or 0
			_skillTimeInclu = _skillTimeInclu or 0

			skillTime =  math.max(_skillTime, skillTime)
			skillTimeInclu = math.max(_skillTimeInclu,skillTimeInclu)

			atkSide = heroData:GetActOn()
		else
			if not isIns then
				skillTime = 0
				skillTimeInclu = Time.deltaTime
			end
		end

		if self._logCtrl:IsLogOpen() then
			local str = string.format("skilltime %s ,skillTimeBack %s",skillTime,skillTimeInclu)
			self._logCtrl:LogNormal(str)
		end

		if heroData then
			atkSide = heroData:GetActOn()
		end
		if not isIns then
			table.insert(skillDataList,{skillData = skillData,time = time,skillTime = skillTime,actionData = actionData,aId = aId})
		end

		if(self._logCtrl:IsLogOpen()) then
			self._logCtrl:LogNormal(string.format("%s|%s使用技能名=%s|refId=%s,表现refid=%s",tostring(aId),tostring(heroData and heroData:GetName() or nil),
					tostring(skillData and skillData:GetSkillName() or nil),tostring(skillRefId),tostring(expressionRefId)))
		end
	end

	self._hurtCounter:StartCounter(atkSide) --设置伤害统计目标

	--printInfoN(tring.format("cur round index %s curbout %s curaction %s",self._curRoundIndex,self._curBout,self._curAction))

	if self._skipBattle then return end --是否跳过战斗

	if self._logCtrl:IsLogOpen() then
		self._logCtrl:LogNormal(string.format("curRound %s curBout %s curAction %s",self._curRoundIndex,self._curBout,self._curAction))
	end

	self._waitTime = 0
	self:SetWaitNextSkillShow(true) ---结束技能等待

	-- 离线战斗回来要追平至离线回合
	if self:IsOfflineRound() then
		--更新血量,生存状态
		local objList = self._objCtrl:GetObjectList()
		for k,v in pairs(objList) do
			v:SynOfflineState(self._currentTime)
		end
		return
	end


	if self._isBackgroundPlay then              --如果玩家退出战斗场景，那就不做战斗表现，直接计时读战报
		local battle = self:GetSpeed() or 1
		local curTimeScale = gLGame:GetBackTimeScale()
		local speed = battle/curTimeScale
		if speed < 1 then
			speed = 1
		end
		local backSkillTime = skillTimeInclu / speed
		self._waitTime = backSkillTime + time
		if self._logCtrl:IsLogOpen() then
			self._logCtrl:LogNormal("后台战斗英雄释放技能的表现时间：" .. tostring(backSkillTime))
		end
		return
	end

	--printInfoN("-------------------------------------------front play ")

	---清理当前技能表现
	local skillList = self._curSkill
	for i, v in ipairs(skillList) do
		v:Destroy()
	end
	self._curSkill = {}

	local preloadSkill = self._preloadSkill
	local skillList = nil
	if preloadSkill then
		local state = self:GetPreloadState(preloadSkill,self._curRoundIndex, self._curBout, self._curAction)
		if state == 1 then
			self:ClearPreloadSkill()
		elseif state == 2 then
			skillList = preloadSkill.skillList
			self._preloadSkill = nil
		end
	end

	---@type LFightSkill
	local skill
	local addTime = skillTime


	local skillIdMap = {}
	local skillRefId = nil
	local bUseSkillMap = {}
	local bUseSKillIdMap = {}
	local index = 1
	for i, v in ipairs(skillDataList) do
		if not v.skillData then -- 没有表现数据 直接执行伤害飘字
			addTime = Mathf.Max(0,addTime)
			self:DealShowAllActionEffects(v.actionData)
		else
			if skillList then
				skill = skillList[index]
				if skill then
					bUseSkillMap[index] = true
					table.insert(self._curSkill,skill)
					bUseSKillIdMap[v.skillData:GetSkillRefId()] = true

					skillRefId = skill:GetSkillId()
					local noSkillHud = false
					if skillIdMap[skillRefId] then
						noSkillHud = true
					end
					skillIdMap[skillRefId] = true

					local curSkillData = skill:GetSkillData()
					if curSkillData and curSkillData:GetSkillRefId() ~= v.skillData:GetSkillRefId() then
						if LOG_INFO_ENABLED then
							printInfoN2("技能打印：",">> 原技能RefId:" .. curSkillData:GetSkillRefId() .. "，当前技能RefId:" .. v.skillData:GetSkillRefId())
						end
						skill:UpdateSkillData(v.skillData,self:GetHero(v.aId),v.actionData)
					end
					skill:Start(noSkillHud)
					index = index + 1
				end
			else
				local atkObj = self:GetHero(v.aId)		-- 没有出手英雄，也直接执行伤害飘字
				if atkObj then
					skill = LFightSkill:New(self,v.skillData,atkObj,v.actionData)
					table.insert(self._curSkill,skill)

					skillRefId = skill:GetSkillId()
					local noSkillHud = false
					if skillIdMap[skillRefId] then
						noSkillHud = true
					end
					skillIdMap[skillRefId] = true

					skill:Start(noSkillHud)
				else
					addTime = Mathf.Max(0,addTime)
					self:DealShowAllActionEffects(v.actionData)
				end
			end
		end
	end

	--删除没有使用过的预加载技能
	if skillList then
		for k,v in pairs(skillList) do
			if not bUseSkillMap[k] then
				v:Destroy()
			end
		end

--[[		for k,v in pairs(skillList) do
			if not bUseSKillIdMap[v._skillData:GetSkillRefId()] then
				v:Destroy()
			end
		end]]
	end

	if self._curSkill and #self._curSkill > 0 then
		---@param v LFightSkill
		for i,v in ipairs(self._curSkill) do
			v:UpdateHerosBgState()
		end
	end
	self._waitTime = time + addTime - 0.0001 --防止延迟一帧

	self:PreloadRoundPlay(self._curRoundIndex, self._curBout, self._curAction + 1)
end

-----------------------------------------------------------------
---获取伤害次数
---@param actionData LFightBoutActionData
function LFightUnit:GetHurtCountFromActionData(actionData)
	local hurtCount = 0
	if not actionData then return hurtCount end
	local aId = actionData:GetAttackId()
	--local playerHero = self:GetHeroData(aId)
	local effectList = actionData:GetEffectList()

	for k,vList in ipairs(effectList) do

		for m,effectOne in ipairs(vList) do

			local eid = effectOne.eid
			local list = effectOne.list

			for _x,effect in ipairs(list) do
				local effectType = effect.type
				local tarData = self:GetHeroData(effect.eId)
				local actionID = tonumber(effect.aId)
				if not tarData or actionID < 0 then
					break
				end

				--local atkData = self:GetHeroData(effect.aId) or playerHero
				if effectType == LFightConst.ACTIONEFFECTENUM_HURT and effect.hitType == 1 then --伤害
					if effect.aId == aId and effect.eId == eid then
						hurtCount = hurtCount + 1
					end
				end
			end
		end
	end

	return hurtCount
end
-----------------------------------------------------------------
---数据模型更新
---@param actionData LFightBoutActionData
function LFightUnit:UpdateHeroDataFromActionData(actionData)
	if not actionData then return end
	local aId = actionData:GetAttackId()
	local playerHero = self:GetHeroData(aId)
	local effectList = actionData:GetEffectList()

	local buffMap = self:RecordTakeJSBuff(effectList,playerHero)

	for k,vList in ipairs(effectList) do
		for m,effectOne in ipairs(vList) do
			local list = effectOne.list
			for _x,effect in ipairs(list) do
				self:DealSingleEffect(effect,playerHero)
				if effect.spurtingList then
					for k,v in ipairs(effect.spurtingList) do
						self:DealSingleEffect(v,playerHero,buffMap[v.eId])
					end
				end

			end
		end
	end
end

---@param playerHero LFightObjectData
function LFightUnit:RecordTakeJSBuff(effectList,playerHero)
	if not playerHero then return {} end
	if not effectList or #effectList < 1 then return {} end

	local buffEffects = {}
	local playerHeroId = playerHero:GetId()
	--- 判断技能是否包含溅射
	for k,vList in ipairs(effectList) do
		for m,effectOne in ipairs(vList) do
			for _x,effect in ipairs(effectOne.list) do
				if effect.aId == playerHeroId then
					if effect.type == LFightConst.ACTIONEFFECTENUM_BUFF and effect.etype == LFightConst.BUFF_TYPE_ADD then
						local buffId = effect.buffId
						if buffId and buffId > 0 then
							local hasJS,buffEffectRef = gModelBattle:CheckBuffHasJianShe(buffId)
							if hasJS then
								table.insert(buffEffects,buffEffectRef)
							end
						end
					end
				end
			end
		end
	end
	if #buffEffects < 1 then return {} end

	local buffAllNum = #buffEffects
	local buffNum = 0
	local buffMap = {}
	for k,vList in ipairs(effectList) do
		for m,effectOne in ipairs(vList) do
			for _x,effect in ipairs(effectOne.list) do
				if effect.aId == playerHeroId then
					if effect.type == LFightConst.ACTIONEFFECTENUM_HURT then
						if effect.spurtingList and #effect.spurtingList > 0 then
							for idx,val in ipairs(effect.spurtingList) do
								buffNum = buffNum + 1
								local buffEffectRef = buffEffects[buffNum]
								if not buffEffectRef then
									buffEffectRef = buffEffects[buffAllNum]
									print("超出下标")
								end
								buffMap[val.eId] = {
									--- 目标id
									targetId = effect.eId,
									targetObj = self:GetHeroData(effect.eId),
									isUse = false,
									buffEffectRef = buffEffectRef,
								}
							end
						end
					end
				end
			end
		end
	end
	return buffMap
end

function LFightUnit:DealSingleEffect(effect,playerHero,takeEffData)

	local logCtrl = self:GetLogCtrl()

	local tarData = self:GetHeroData(effect.eId)
	if not tarData then return end

	local effectType = effect.type

	local atkData = self:GetHeroData(effect.aId) or playerHero
	if effectType == LFightConst.ACTIONEFFECTENUM_HURT then --伤害
		local hurt = effect.hurt

		local side = self:GetOppositeSide(tarData:GetActOn())
		self:AddHurtCnt(side,hurt)
		--isHurtChange = true
		local oldHp = tarData:GetHp()

		if effect.ht == LFightConst.HURT_TYPE_PARRYING then
			tarData:UpdateBlockData()
		else
			local hp = effect.afterHp
			tarData:RefreshCurHp(hp)
		end

		if effect.dead then
			local canRelive = self:CheckCanRelive(effect.eId)
			tarData:SetDead(true,canRelive)
		end
		tarData:UpdateBearDamageCount(hurt)
		if atkData then
			atkData:UpdateDamageCount(hurt)
		end

		--if takeEffData and takeEffData.buffEffectRef then
		--	---@type LFightObject
		--	local tarObj = self:GetHero(effect.eId)
		--	---@type LFightObject
		--	local takeObj = self:GetHero(takeEffData.targetId)
		--	if tarObj and takeObj then
		--		-- 播放溅射
		--		local buffEffectRef = takeEffData.buffEffectRef
		--		if buffEffectRef and not string.isempty(buffEffectRef.showEffect) then
		--			local effectCtrl = self:GetEffectCtrl()
		--			if side == LFightConst.SIDE_TEAM_A then
		--			elseif side == LFightConst.SIDE_TEAM_B then
		--			end
		--			local playTime = 1
		--			local dissipateTime = 1
		--			local tarDisplayTrans = tarObj:GetDisplayObj():GetDisplayTrans()
		--			local tarPos = tarObj:GetDisplayObj():GetPos()
		--			local dir = takeObj:GetDirection()
		--			---@type LFightEffect
		--			local _effect = effectCtrl:MakeEffectObject(tarDisplayTrans,buffEffectRef.showEffect,tarPos,dir,1.22,playTime,dissipateTime)
		--			_effect:SetBullet(true, takeObj:GetDisplayObj():GetPos(), playTime, 0,1)
		--			_effect:SetEffectPara({
		--				isUpperLayer= takeObj:IsUpperLayer(),
		--				scale = 1,
		--			})
		--			effectCtrl:AddEffect(_effect)
		--		end
		--	end
		--end


		if logCtrl:IsLogOpen() then
			logCtrl:LogHpChange(tarData:GetId(),tarData:GetMaxHp(),tarData:GetHp(),oldHp,-hurt)
		end

	elseif effectType == LFightConst.ACTIONEFFECTENUM_BUFF then --buff
		local buff = {}
		buff.buffUniqueId = effect.buffUniqueId
		buff.buffId = effect.buffId
		buff.round = effect.round
		buff.startRound = self._roundCount == 0 and 1 or self._roundCount
		buff.currentRound = effect.round
		tarData:DoBuffUpdate(buff,effect.etype)

		if effect.etype == LFightConst.BUFF_TYPE_REMOVE then
			self:InsertWaitRemove(effect.buffUniqueId)
		end

	elseif effectType == LFightConst.ACTIONEFFECTENUM_TREATS then --治疗
		local treat = effect.treat
		local oldHp = tarData:GetHp()
		local hp = effect.afterHp
		tarData:RefreshCurHp(hp)

		if effect.relive then
			tarData:SetDead(false)
		end

		if logCtrl:IsLogOpen() then
			logCtrl:LogHpChange(tarData:GetId(),tarData:GetMaxHp(),tarData:GetHp(),oldHp,treat)
		end

		if atkData then
			atkData:UpdateTreatmentCount(treat)
		end
	elseif effectType == LFightConst.ACTIONEFFECTENUM_SHIELD then --护盾
		local shield = {}
		shield.buffUniqueId = effect.buffUniqueId
		shield.shieldUniqueId = effect.shieldUniqueId
		shield.maxHP = effect.hp
		shield.curHP = effect.hp
		tarData:AddShieldData(shield)

	elseif effectType == LFightConst.ACTIONEFFECTENUM_PSHIELD then --格挡盾
		local block = {}
		block.buffUniqueId = effect.buffUniqueId
		block.blockUniqueId = effect.blockUniqueId
		block.maxCount = effect.count
		block.curCount = effect.count
		tarData:AddBlockData(block)

	elseif effectType == LFightConst.ACTIONEFFECTENUM_ANGER then --怒气
		local anger = {}
		anger.buffUniqueId = effect.buffUniqueId
		anger.angerValue = effect.angerValue
		tarData:AddAngerData(anger)

	elseif effectType == LFightConst.ACTIONEFFECTENUM_SHIELDHURT then --护盾抵挡伤害
		local shield = {}
		shield.shieldUniqueId = effect.shieldUniqueId
		shield.hurt = - effect.hurt

		tarData:UpdateBearDamageCount(shield.hurt)
		if atkData then
			atkData:UpdateDamageCount(shield.hurt)
		end
		tarData:UpdateShieldData(shield)
	elseif effectType == LFightConst.ACTIONEFFECTENUM_POSITION then

--[[		local side = tarData:GetActOn()
		local oldIndex = effect.oldIndex
		local heroData = self:GetHeroDataByIndex(side,oldIndex)
		if heroData then
			heroData:UpdateIndex(effect)
		end
		local newIndex = effect.newIndex
		heroData = self:GetHeroDataByIndex(side,newIndex)
		if heroData then
			heroData:UpdateIndex(effect)
		end]]


		local eId = effect.eId
		local heroData
		for k,v in pairs(self._mapFormationData) do
			if v:GetId() == eId then
				heroData = v
				break
			end
		end
		if heroData then
			heroData:UpdateIndex1(effect)
		end

		--self:UpdateHeroDataMap()
	elseif effectType == LFightConst.ACTIONEFFECTENUM_SUMMON then
		self:AddSummonHeroData(effect)
	elseif effectType == LFightConst.ACTIONEFFECTENUM_ROUND then
		tarData:UpdateRoundData(effect)
	end


	self:UpdateBloodPercentBack()

end

function LFightUnit:UpdateBloodPercentBack()
	if not self._isBackgroundPlay then
		return
	end

	if not self._mapFormationData then
		return
	end
	local totalHpA = 0
	local totalHpB = 0
	local curHpA = 0
	local curHpB = 0
	for k,v in pairs(self._mapFormationData) do
		local objType = v:GetArtifactType()
		if objType == LFightConst.OBJ_NORMAL then
			local side = v:GetActOn()
			if side == LFightConst.SIDE_TEAM_A then
				totalHpA = totalHpA + v:GetMaxHp()
				curHpA = curHpA + v:GetHp()
			else
				totalHpB = totalHpB + v:GetMaxHp()
				curHpB = curHpB + v:GetHp()
			end
		end
	end

	local percentA = 1
	if totalHpA >0 then
		percentA = curHpA/totalHpA
	end

	local percentB = 1
	if totalHpB >0 then
		percentB = curHpB/totalHpB
	end

	self:RefreshBloodPercent(true,percentA)
	self:RefreshBloodPercent(false,percentB)

end

function LFightUnit:AddHurtCnt(side,hurt)

	local curHurt = self._teamHurtCnt[side] or 0
	curHurt = curHurt + hurt
	self._teamHurtCnt[side] = curHurt


end

function LFightUnit:InitShowHurtCnt()
	if not self._teamShowHurtCnt then
		self._teamShowHurtCnt = {}
		self._teamShowHurtCnt[LFightConst.SIDE_TEAM_A] = self:GetTeamHurtCnt(LFightConst.SIDE_TEAM_A)
		self._teamShowHurtCnt[LFightConst.SIDE_TEAM_B] = self:GetTeamHurtCnt(LFightConst.SIDE_TEAM_B)

		FireEvent(EventNames.INIT_HURT_CNT)
	end

end

function LFightUnit:AddShowHurtCnt(side,hurt)

	--if LOG_INFO_ENABLED then
	--	print(string.format("add hurt side %s,hurt %s",side,hurt))
	--end

	self:InitShowHurtCnt()

	local curHurtCnt = self._teamShowHurtCnt[side]
	curHurtCnt = curHurtCnt +  hurt

	self._teamShowHurtCnt[side] = curHurtCnt

	if not self._isBackgroundPlay then
		FireEvent(EventNames.BATTLE_HURT_MAX_COUNT_UPDATE)
	end
end

function LFightUnit:GetTeamHurtCnt(side)
	return self._teamHurtCnt[side] or 0
end

function LFightUnit:GetTeamShowHurtCnt(side)
	return self._teamShowHurtCnt and self._teamShowHurtCnt[side] or 0
end

function LFightUnit:GetMonsterAttrId(side)
	return self._battleReportData:GetMonsterAttrId(side)
end

function LFightUnit:UpdateHeroDataBuffData()
	local round = self._round
	local nowRound = self._roundCount
	local checkBuff = false
	if(round ~= nowRound) then
		self._round = nowRound
		checkBuff = true
	end
	if checkBuff then
		for i, heroData in pairs(self._mapFormationData) do
			heroData:OnUpdateBuffRound(nowRound)
		end
		checkBuff = false
		FireEvent(EventNames.BUFF_UPDATE,true)--刷新buff回合数
	end
end

