function LFightUnit:OnRoundUpdate(round)
	for k,v in pairs(self._mapFormationData) do
		v:OnRoundUpdate(round)
	end
end

function LFightUnit:OnRoundDivineUpdate(round)
	for k,v in pairs(self._mapFormationData) do
		v:OnRoundDivineUpdate(round)
	end
end

function LFightUnit:OnObjRoundUpdate()
	local nowRound = self:GetRoundCount()
	local roundRecord = self._roundRecord
	if roundRecord == nowRound then
		return
	end
	self._roundRecord = nowRound
	local objList = self._objCtrl:GetObjectList()
	for k,v in ipairs(objList) do
		v:OnUpdateBuffRound(nowRound)
	end
end

