--设置战斗中双方玩家英雄数据
function LFightUnit:InitFormationData()

	local formationDataA = self._battleReportData:GetFormationA()
	local formationDataB = self._battleReportData:GetFormationB()

	local mapFormationData = {}
	self._mapFormationData = mapFormationData

	local teamId = LFightConst.ACTON_TEAM_A

	local formationA = {}
	self._formationA = formationA
	local teamAGrids = formationDataA.grids

	for k,v in ipairs(teamAGrids) do
		local heroA = LFightObjectData:New()
		heroA:InitializationHeroData(v,teamId)
		table.insert(formationA, heroA)
		mapFormationData[v.id] = heroA
	end

	-- 神器或精灵数据暂未完善
	local combatUnits = formationDataA.combatUnits
	if combatUnits then
		for k,v in ipairs(combatUnits) do
			---@type LFightObjectData
			local unitData = LFightObjectData:New()
			local type = v.type
			if type == LFightConst.OBJ_ARTIFACT then
				local initCD = v.data and v.data.initCD or 0
				unitData:InitializeArtifactData(tostring(v.id),v.refId,teamId,v.campSkillIdList,initCD)
				table.insert(self._teamAArtifact, unitData)
				mapFormationData[tostring(v.id)] = unitData

				self._teamAArtifactID = v.refId
				self._selfArtifactData = v.data
			elseif type == LFightConst.OBJ_TREASURE then
				unitData:InitTreasureData(v,teamId)
				mapFormationData[tostring(v.id)] = unitData

				self:AddBattleUnitData(unitData,type,teamId)
			elseif type == LFightConst.OBJ_DIVINEWEAPON then
				unitData:InitDivineWeaponData(v,teamId)
				mapFormationData[tostring(v.id)] = unitData
				self:AddBattleUnitData(unitData,type,teamId)
			end
		end

	end


	teamId = LFightConst.ACTON_TEAM_B

	local formationB = {}
	self._formationB = formationB
	local teamBGrids = formationDataB.grids
	for k,v in ipairs(teamBGrids) do
		local heroB = LFightObjectData:New()
		heroB:InitializationHeroData(v,teamId)
		table.insert(formationB, heroB)
		mapFormationData[v.id] = heroB
	end

	-- 神器或精灵数据暂未完善
	local combatUnits = formationDataB.combatUnits
	if combatUnits then
		for k, v in ipairs(combatUnits) do
			local unitData = LFightObjectData:New()
			local type = v.type
			if type == LFightConst.OBJ_ARTIFACT then
				local initCD = v.data and v.data.initCD or 0
				unitData:InitializeArtifactData(tostring(v.id),v.refId,teamId,v.campSkillIdList,initCD)
				table.insert(self._teamBArtifact, unitData)
				mapFormationData[tostring(v.id)] = unitData

				self._teamBArtifactID = v.refId
				self._otherArtifactData = v.data
			elseif type == LFightConst.OBJ_TREASURE then
				unitData:InitTreasureData(v,teamId)
				mapFormationData[tostring(v.id)] = unitData
				self:AddBattleUnitData(unitData,type,teamId)
			elseif type == LFightConst.OBJ_DIVINEWEAPON then
				unitData:InitDivineWeaponData(v,teamId)
				mapFormationData[tostring(v.id)] = unitData
				self:AddBattleUnitData(unitData,type,teamId)
			end
		end
	end

	self:UpdateHeroDataMap()

	self:InitHeroReliveSkillRecord()
end

function LFightUnit:InitHeroReliveSkillRecord()
	local record = {}
	for k,v in pairs(self._mapFormationData) do
		local tempRecord = v:GetReliveSkillRecord()
		for k1,v1 in pairs(tempRecord) do
			local map = record[k1]
			if not map then
				map = {}
				record[k1] = map
			end

			for k2,v2 in pairs(v1) do
				map[k2] = v2
			end
		end
	end

	self._reliveSkillRecord= record
end

function LFightUnit:AddBattleUnitData(unitdata,type,side)
	local unitDataList = self._unitDataList
	if not unitDataList then
		unitDataList = {}
		self._unitDataList = unitDataList
	end
	local map = unitDataList[type]
	if not map then
		map = {}
		unitDataList[type] = map
	end
	map[side] = unitdata
end

function LFightUnit:UpdateHeroDataMap()
	self._heroDataByIndex = {
		[LFightConst.SIDE_TEAM_A] = {},
		[LFightConst.SIDE_TEAM_B] = {},
	}

	for k,v in pairs(self._mapFormationData) do
		local objType = v:GetArtifactType()
		if objType == LFightConst.OBJ_NORMAL or objType == LFightConst.OBJ_SUMMON or objType == LFightConst.OBJ_PET then
			local side = v:GetActOn()
			local index = v:GetIndex()
			self._heroDataByIndex[side][index] = v
		end
	end

end

function LFightUnit:GetHeroDataByIndex(side,index)
	if self._heroDataByIndex then
		return self._heroDataByIndex[side][index]
	end
end

