---执行伤害表现
---
function LFightUnit:DealShowAllActionEffects(actionData)
	local effectList = actionData:GetEffectList()
	for k,v in ipairs(effectList) do
		self:DealShowHurt(v)
	end

end
function LFightUnit:ShowDealEffect()
	local warnEff = LFightWarn.New()
	self._deadWarnEff = warnEff
	self._deadWarnEff:Create(self:GetEffectRootTrans(), true, Vector3.zero)

	local dp = LDisplayEffect:New()
	self._deadEffect = dp
	dp:CreateEffect(self:GetEffectRootTrans(), "fx_manjingtou")
	dp:SetResTag(CS.RES_TAG_SCENE)
	dp:SetLoadedFunction(function()
		if self:IsDestroy() then return end
		if not self._deadEffect or not self._deadEffect:IsDpValid() then return end
		local dpTrans = self._deadEffect:GetDisplayTrans()
		local isWin = self._battleReportData:GetWinner() == 1
		local pos = Vector3(-2,0,0)
		if isWin then
			pos.x = 2
		end
		dpTrans.localPosition = pos
	end)
	dp:StartLoadEffect()


end
function LFightUnit:ShowLastEffect()
	if self._isLastEffShowed then return end

	self._isLastEffShowed = true
	self._isShowingLastEff = true
	self:ShowDealEffect()
	gLGame:SetGameTimeScaleApply(0.3)
	self:StopDelayResetScaleTimer()
	self._delayResetScaleTimer = LxTimer.DelayTimeCall(function()
		gLGame:SetGameTimeScaleApply(1)
		self._isShowingLastEff = false
		--self._isLastEffShowed = true
		--self:OnBattleEnd()

	end, 1.5, true)
end

---@param lBattleSkill LFightSkill
function LFightUnit:DealShowHurt(effectList,bPlayHit,playNum,offsetPos,lBattleSkill)
	if self._isLastAtk and not self._isAllboTarget then
		self:ShowLastEffect()
	end
	if not effectList then return end
	bPlayHit = bPlayHit or LFightConst.PLAY_HIT_ACTION_NONE
	playNum = playNum or {}
	offsetPos = offsetPos or Vector3(0,0,0)
	--local hudCtrl = self:GetHudCtrl()
	--local intervalTime = 0.2
	local isBuffUpdate = false
	local isHurtType = false  -- 连击而且类型混杂的情况下，优先显示总伤害

	--local curOffset = offsetPos
	local isLogOpen= self._logCtrl:IsLogOpen()

	local hudDataList ={}
	local time = self:GetTime()

	--local deadStateList = {}

	local buffExpreCtrl = self._buffExpreCtrl
	local effectCtrl = self:GetEffectCtrl()

	---@type table<string,LFightObject>
	local heroRecord = {}

	local cBuff103HurtList,calcDelayTime = self:CollectBuff103HurtList(effectList,lBattleSkill)
	local needDelayTime = self:CheckBombDelayTime(effectList)
	local doHurtTime = time + calcDelayTime + needDelayTime

	for k,effectStruct in ipairs(effectList) do
		--local eid = effectStruct.eid
		local list = self:RejectQueer(effectStruct.list)

		--local buffEffActMap = self:CollectBuffActMap(list)

		--- 2024/7/9： http://192.168.16.2:3002/issues/838 护盾吸收伤害导致伤害<1时不飘免伤（客户端）
		---@type boolean 是否为护盾格挡伤害，如果护盾格挡后还有伤害且为0，则不飘免伤

		---@type boolean 护盾抵消伤害
		local isOffsetInjury = self:CheckOffsetInjury(list)

		--local addOffset = false
		for m,effect in ipairs(list) do
			local effectType = effect.type
			local aId,eId = effect.aId,effect.eId
			local atkHero = self:GetHero(aId)
			local tarHero = self:GetHero(eId)

			--local actionID = tonumber(aId)
			if not tarHero or not tarHero:IsOnGridObj() then break end

			local atkSide = nil
			if atkHero then
				atkSide = atkHero:GetSide()
			else
				local side = tarHero:GetSide()
				atkSide = self:GetOppositeSide(side)
			end

			local tarPos = tarHero:GetTopNodePos()
			local pos = tarPos and tarPos:Clone() or Vector3.zero

			local hudData = nil

			if effectType == LFightConst.ACTIONEFFECTENUM_HURT then --伤害表现效果
				local hurt = math.ceil(effect.hurt)
				local ht = effect.ht
				local dead = effect.dead
				local afterHp = effect.afterHp or 0
				--self:ChangeTeamHP(tarHero,afterHp,playNum,time)
				local tempPlayNum = playNum
				if ht == LFightConst.HURT_TYPE_PARRYING or ht == LFightConst.HURT_TYPE_BEHEAD
						or LFightConst.NOT_SPLIT_PLAYNUM[ht] then
					tempPlayNum ={}
				end

				if effect.hitType == 0 then --非技能对应伤害，不分段飘字
					--- http://192.168.16.2:3002/issues/757
					--- 此类多段伤害表现，在播放最后伤害受击后才倒地（相当于是打了空血条小人）
					if type(playNum) == "table" and #playNum > 0 then
					else
						tempPlayNum = {}
					end
				end

				tarHero:UpdateBlood(afterHp,tempPlayNum,doHurtTime)

				if ht == LFightConst.HURT_TYPE_PARRYING then
					--playNum = {}    -- 格挡不受配置次数影响
					tarHero:UpdateBlockData()
				end

				local deadDelay = 0


				--- 2024/11/19：后端修改逻辑，以前 hurtEffect 的 dead 是先发 0 再发 1，现在直接下发 1
				---@type boolean 是否显示飘血数据
				local showHudData = true
				if not dead then
					if hurt < 1 and  ht ~= LFightConst.HURT_TYPE_PARRYING and ht ~= LFightConst.HURT_TYPE_MISS
							--- http://192.168.16.2:3002/issues/705
							--- 若CombatDamageTypeRef（伤害类型表）1004=护盾这种伤害，导致的本次伤害减免至0，不飘免伤表现buff_txt_shqm_1
							and ht ~= LFightConst.HURT_TYPE_SHIELD
							--- 2024/7/10：分摊<0的时候，不飘免伤
							and ht ~= LFightConst.HURT_TYPE_DIVIDE_EQUALLY then
						--优化需求 #1317:1. 当出现“因为免伤太高，把本次伤害减免至0”的时候，不飘伤害0，而变更为飘艺术字“伤害全免”（美术资源名：buff_txt_shqm_1）

						--- 2024/9/11：普通伤害类型，排除飘免伤
						if not isOffsetInjury and ht ~= LFightConst.HURT_TYPE_GENERAL_ATTACK then
							hudData ={
								targetHeroId = eId ,
								pos = pos+ offsetPos,
								time = doHurtTime,
								changeType = LFightConst.HURT_TIP,
								text = "buff_txt_shqm_1"
							}
						end
						showHudData = false
					else
						if ht == LFightConst.HURT_TYPE_DIVIDE_EQUALLY and hurt < 1 then
							--- 分摊没有数值的话，直接取消飘字
							showHudData = false
						end
					end
				else
					deadDelay = gModelSkill:GetTotalDelay(tempPlayNum)
				end
				
				if showHudData then
					local text
					local showType = ht
					local actHurt = hurt
					local isPARRYING = ht == LFightConst.HURT_TYPE_PARRYING
					if isPARRYING then
						actHurt = nil
						local amageTypeRef = GameTable.BattleDamageTypeRef[showType]
						text = amageTypeRef and amageTypeRef.name
						showType = LFightConst.HURT_TIP
					else
						if actHurt and actHurt < 1 then
							actHurt = nil
							local amageTypeRef = GameTable.BattleDamageTypeRef[showType]
							text = amageTypeRef and amageTypeRef.name
							showType = LFightConst.HURT_TIP
						end
					end
					hudData ={
						targetHeroId = eId ,
						pos = pos + offsetPos,
						time = doHurtTime,
						hurt = actHurt,
						changeType = showType,
						isLeft = tarHero:GetSide() == LFightConst.SIDE_TEAM_A,
						playNum = tempPlayNum,
						text = text,
					}
				end

				if ht ~= LFightConst.HURT_TYPE_PARRYING then
					isHurtType = true
					--printErrorN("cur hurt -----------------"..hurt)
					self:ShowHurtCount(true,hurt,tempPlayNum,doHurtTime,atkSide)
				end

				if dead then
					isBuffUpdate = true
					local canRelive = self:CheckCanRelive(eId)
					buffExpreCtrl:SetSpecialExpressVisible(tarHero,false)
					tarHero:DoDead(doHurtTime,nil,canRelive,deadDelay)
					--printInfoN("-------------------dodead id "..eId)
					--tarHero:PlayHitSound()
					--优化需求 #3967 【战斗系统】战斗多段表现伤害的受击效果优化
					--hudData.hitAction = LFightConst.HIT_ACT_SOUND_ONLY
				end

				if hudData then
					if ht ~= LFightConst.HURT_TYPE_MISS then
						if bPlayHit == LFightConst.PLAY_HIT_ACTION_SKILL then	--播放技能受击动画
							--tarHero:PlaySkillHitAni()
							--tarHero:PlayHitSound()
							--优化需求 #3967 【战斗系统】战斗多段表现伤害的受击效果优化
							hudData.hitAction = LFightConst.HIT_ACT_SOUND_AND_SKILLHIT

						elseif bPlayHit == LFightConst.PLAY_HIT_ACTION_NORMAL then
							--tarHero:PlayHitAni()
							--tarHero:PlayHitSound()
							--优化需求 #3967 【战斗系统】战斗多段表现伤害的受击效果优化
							hudData.hitAction = LFightConst.HIT_ACT_SOUND_AND_HIT
						end
					end
					--非技能对应伤害， 不播放受击
					if not dead and effect.hitType == 0 and ht ~= LFightConst.HURT_TYPE_SPUTTERING then
						hudData.hitAction = nil
					end

					--- 判断 buff 是否有受击特效
					local isHasHitBuffEffShow,buffRef = tarHero:CheckHasHitBuffEffShow(ht)
					if isHasHitBuffEffShow and buffRef ~= nil then
						--- 受击时表现
						local buffEffPos = tarHero:GetPosition()
						local effectRootTrans = tarHero:GetDpObject():GetDisplayTrans()
						local buffEffShowPos = buffRef.buffEffShowPos
						local localPos
						if buffEffShowPos and buffEffShowPos > 0 then
							local isFormation = buffEffShowPos == LFightConst.BUFF_POS_SELF or buffEffShowPos == LFightConst.BUFF_POS_OTHER
							if not isFormation then
								local buffShowPos = tarHero:GetBuffEffShowPosByBuffEffShowPos(buffEffShowPos,tarHero:GetObjScale())
								if buffShowPos then
									---@type LDisplaySpine
									local tarHeroDP = tarHero:GetTransformDisplayObj()
									effectRootTrans = tarHeroDP:GetDisplayTrans()
									localPos = buffShowPos
								end
							end
						end
						---@type LFightEffect
						local _buffEff = effectCtrl:MakeEffectObject(effectRootTrans,buffRef.buffEffShow,buffEffPos,tarHero:GetDirection(),0,2,0)
						_buffEff:SetEffectPara({
							scale = 1,
							localPos = localPos,
							buffId = buffRef.refId,
						})
						effectCtrl:AddEffect(_buffEff)
					end
				end
			elseif effectType == LFightConst.ACTIONEFFECTENUM_TREATS then --治疗表现效果

				local reliveSkillShow = false
				local isExpress = false
				if effect.express and effect.express > 0 then
					isExpress = true
					local skin = tarHero:GetSkinId()
					local expressId = gModelSkill:GetSkinExpress(skin,effect.express)
					if expressId then
						local buffExpress = buffExpreCtrl:GetBuffExpre(expressId)
						local para =
						{
							atkObj = atkHero,
							targetObj = tarHero,
							curTime = self:GetTime()
						}
						buffExpress:StartRun(para)
						buffExpreCtrl:AddRunningExpre(buffExpress)
						reliveSkillShow = true
					end
				end

				local treat = math.ceil(effect.treat)
				if effect.relive then
					--printInfoN("-------------------dorelive id "..eId)
					--local noAct = eId == aId
					tarHero:DoRelive(time,false,reliveSkillShow)
					isBuffUpdate = true

					buffExpreCtrl:SetSpecialExpressVisible(tarHero,true)
				end


				local afterHp = effect.afterHp or 0
				--self:ChangeTeamHP(tarHero,afterHp,playNum,time)
				local tempPlayNum = effect.hitType == 0 and {} or playNum

				tarHero:UpdateBlood(afterHp,tempPlayNum,time)

				if treat < 1 then
					--优化需求 #1317:2. 当出现“因为受疗属性太低，把本次所受到的治疗值降成0”的时候，不飘回血0，而变更为飘艺术字“受疗缺失”（美术资源名：buff_txt_slqs_1）

					--hudData ={
					--	targetHeroId = eId ,
					--	pos = pos+ offsetPos,
					--	time = time,
					--	changeType = LFightConst.HURT_TIP,
					--	text = "buff_txt_slqs_1",
					--}
				else
					hudData ={
						targetHeroId = eId ,
						pos = pos+ offsetPos,
						time = time,
						hurt = treat,
						changeType = LFightConst.HURT_TYPE_HEAL,
						playNum =  tempPlayNum,
						isLeft = tarHero:GetSide() == LFightConst.SIDE_TEAM_A,
					}

					--- 针对技能复活，且 effect.express == 0 时处理
					if not isExpress and effect.skill and effect.skill > 0 then
						local tEffectList = gModelSkill:GetEffectList(effect.skill) or {}
						if tEffectList and #tEffectList > 0 then
							if tarHero:IsDead() or effect.relive then
								for _k,effectRefId in ipairs(tEffectList) do
									---@type V_SkillEffectRef
									local skillEffectRef = gModelSkill:GetSkillEffectRef(effectRefId)
									if skillEffectRef and skillEffectRef.effectType == 3 then
										if not string.isempty(skillEffectRef.baseValue2) then
											local baseValue2s = string.split(skillEffectRef.baseValue2,",")
											if baseValue2s[1] then
												local first = string.split(baseValue2s[1],"=")
												local index1 = checknumber(first[1])
												if index1 and index1 == 1 then
													tarHero:PlayAni_TreatAni(time + 0.1)
												end
											end
										end
									end
								end
							end
						end
					end
				end

				local t_effectType = effect.effectType
				if t_effectType and t_effectType > 0 then
					if t_effectType == 1 then
						--- 1=禁疗
						local amageTypeRef = GameTable.BattleDamageTypeRef[LFightConst.HURT_TYPE_BOOM]
						if amageTypeRef and not string.isempty(amageTypeRef.name) then
							hudData ={
								targetHeroId = eId ,
								pos = pos + offsetPos,
								time = time,
								changeType = LFightConst.HURT_TIP,
								text = amageTypeRef.name
							}
						end
					end
				end

				--addOffset = true

				if not isHurtType then
					self:ShowHurtCount(false,treat,tempPlayNum,time,atkSide)
					--FireEvent(EventNames.BATTLE_HURT_COUNT_UPDATE,false,treat)
				end
			elseif effectType == LFightConst.ACTIONEFFECTENUM_BUFF then --buff表现效果
				local buffId = effect.buffId
				---@type V_BuffRef
				local buffRefData = self:GetBuffRef(buffId)
				--printInfoN(string.format("--------- buffid %s buffuniqueId %s etype %s",buffId,effect.buffUniqueId,effect.etype))
				if buffRefData then
					local buffUniqueId = effect.buffUniqueId
					local etype = effect.etype
					local buff = {}
					buff.buffUniqueId = buffUniqueId
					buff.buffId = buffId
					buff.round = effect.round
					buff.startRound = self._roundCount == 0 and 1 or self._roundCount
					buff.currentRound = effect.round
					tarHero:DoBuffUpdate(buff,etype)

					self._buffEffectIs92 = self:CheckBuffEffectIs92(buffId)

					local isSummonBuff = gModelBattle:CheckBuffEffectIsSummon(buffId)
					---@type LFightObject
					local summonHero
					if isSummonBuff then
						summonHero = self:GetSummonHero(buffUniqueId)
					end

					--- buff 特效表现
					local buffEffShow = buffRefData.buffEffShow
					--- 拥有 buff 特效表现
					local isHasBuffEffShow = not string.isempty(buffEffShow)
					local buffEffShowPos = buffRefData.buffEffShowPos
					local isOtherPos = buffEffShowPos == LFightConst.BUFF_POS_OTHER
					local isFormationBuff = buffEffShowPos == LFightConst.BUFF_POS_SELF or isOtherPos
					local showSide = atkSide
					local buffEffShowType = buffRefData.buffEffShowType
					if isOtherPos then
						showSide = self:GetOppositeSide(showSide)
					end
					local hasHurtShields = gModelBattle:CheckBuffHasHurtShields(buffId)
					local createBuffEff = false
					local isAdd = etype == LFightConst.BUFF_TYPE_ADD
					local checkAdd = isAdd
					if hasHurtShields then
						--- 如果对应的 buff(BuffRef)配置里的 buff效果(BuffEffectRef)存在103类型，且 etype 是更新时，则需要将
						--- 之前同类型创建的特效给移除掉重新创建，buffUniqueId 是相同，服务端变更的是 buffRefId
						if etype == LFightConst.BUFF_TYPE_UPDATE then
							if isHasBuffEffShow and isFormationBuff then
								local recordSideMap = self._rcdFormationBuffMap[showSide]
								local recordBuffGroupMap = recordSideMap and recordSideMap[buffEffShowType]
								if recordBuffGroupMap ~= nil then
									local changeEffect = false
									if hasHurtShields then
										local groundBUId = recordBuffGroupMap.buffUniqueId
										local groundBuffId = recordBuffGroupMap.buffId
										if groundBUId == buffUniqueId and groundBuffId ~= buffId then
											changeEffect = true
											effectCtrl:DestroyEffect(recordBuffGroupMap.effect)
											self._rcdFormationBuffMap[showSide][buffEffShowType] = nil
										end
									end
									if changeEffect then
										checkAdd = true
									end
								end
							end
						end
					end
					if checkAdd and isHasBuffEffShow then
						if isFormationBuff then
							local isCreateEff = true
							if buffEffShowType and buffEffShowType > 0 then
								local recordSideMap = self._rcdFormationBuffMap[showSide]
								local recordBuffGroupMap = recordSideMap and recordSideMap[buffEffShowType]
								if recordBuffGroupMap ~= nil then
									isCreateEff = false
								end
							end
							if isCreateEff then
								---@type LDisplaySpine
								local tarHeroDP = tarHero:GetTransformDisplayObj()
								local effectRootTrans = self:GetEffectRootTrans()
								local buffEffPos = self:GetFormationCenterPosition(showSide)
								local localPos
								if buffEffShowPos and buffEffShowPos > 0 and not tarHero:GetChangeSpineState() then
									local buffShowPos = tarHero:GetBuffEffShowPosByBuffEffShowPos(buffEffShowPos,tarHero:GetObjScale())
									if buffShowPos then
										effectRootTrans = tarHeroDP:GetDisplayTrans()
										buffEffPos = tarHero:GetPosition()
										localPos = buffShowPos
									end
								end
								local isPersistence = effect.round > 0
								if hasHurtShields then
									isPersistence = true
								end
								local data
								local playTime = 2
								---@type LFightEffect
								local _buffEff = effectCtrl:MakeEffectObject(effectRootTrans,buffEffShow,buffEffPos,atkHero:GetDirection(),0,playTime,0)
								_buffEff:SetEffectPara({
									scale = 1,
									isPersistence = isPersistence,
									buffId = buffId,
									extraData = data,
								})
								effectCtrl:AddEffect(_buffEff)
								isCreateEff = true

								local tRecordSideMap = self._rcdFormationBuffMap[showSide]
								if tRecordSideMap == nil then
									tRecordSideMap = {}
									self._rcdFormationBuffMap[showSide] = tRecordSideMap
								end
								tRecordSideMap[buffEffShowType] = {
									effect = _buffEff,
									buffUniqueId = buffUniqueId,
									buffId = buffId,
								}
								createBuffEff = true
							end
						else
							if buffEffShowType and buffEffShowType < 1 then
								--- 无分组
								local recordBuffCreateMap = self._rcdBuffCreateMap
								if not recordBuffCreateMap then
									recordBuffCreateMap = {}
									self._rcdBuffCreateMap = recordBuffCreateMap
								end
								local tarHeroId = tarHero:GetId()
								local recordIdMap = recordBuffCreateMap[tarHeroId]
								if not recordIdMap then
									recordIdMap = {}
									recordBuffCreateMap[tarHeroId] = recordIdMap
								end
								if not recordIdMap[buffId] then
									---@type LDisplaySpine
									local tarHeroDP = tarHero:GetTransformDisplayObj()
									local tarHeroTrans = tarHeroDP:GetDisplayTrans()
									local tarHeroPos = tarHero:GetPosition()
									local localPos
									if buffEffShowPos and buffEffShowPos > 0 and not tarHero:GetChangeSpineState() then
										local buffShowPos = tarHero:GetBuffEffShowPosByBuffEffShowPos(buffEffShowPos,tarHero:GetObjScale())
										if buffShowPos then
											localPos = buffShowPos
										end
									end
									local startTime = 0
									local playTime = 2
									local direction = tarHero:GetDirection()
									---@type LFightEffect
									local _buffEff = effectCtrl:MakeEffectObject(tarHeroTrans,buffEffShow,tarHeroPos,direction,startTime,playTime,0)
									_buffEff:SetEffectPara({
										scale = 1,
										isPersistence = effect.round > 0,
										targetObj = tarHero,
										localPos = localPos,
										buffId = buffId,
									})
									effectCtrl:AddEffect(_buffEff)
									recordIdMap[buffId] = {
										effect = _buffEff,
										buffUniqueId = buffUniqueId,
										buffId = buffId,
									}
								end
							end
						end

						----- 技能表那边增加，这里不做处理
						--local buffEffShowTime = buffRefData.buffEffShowTime
						--if buffEffShowTime == 2 and effect.show then
						--	--- 受击时表现
						--	local effectCtrl = self:GetEffectCtrl()
						--	local buffEffPos = tarHero:GetPosition()
						--	local tarHeroTran = tarHero:GetDpObject():GetDisplayTrans()
						--	---@type LFightEffect
						--	local _buffEff = effectCtrl:MakeEffectObject(tarHeroTran,buffEffShow,buffEffPos,tarHero:GetDirection(),0,2,0)
						--	_buffEff:SetEffectPara({
						--		scale = 1,
						--	})
						--	effectCtrl:AddEffect(_buffEff)
						--end
					end


					local id = tarHero:GetId()
					if not createBuffEff then
						heroRecord[id] = tarHero
					end
					local buffName = ccLngText(buffRefData.name)
					local isDead = tarHero:IsDead()
					if isAdd then
						local isShowAfterDead = gModelBattle:IsShowAfterDead(buff.buffId)
						if (isDead and isShowAfterDead) or (not isDead and not isShowAfterDead) then
							local addOrReduceBuff = buffRefData.show
							if not string.isempty(addOrReduceBuff) and effect.show then
								hudData = {
									targetHeroId = eId ,
									pos = pos+ offsetPos,
									time = time,
									changeType = LFightConst.HURT_TYPE_BUFF,
									text = buffName,
									addOrReduceBuff = addOrReduceBuff,
								}
							end
						end
						---buff 表现
						local showEff = tarHero:GetShowEffRef()
						local buffExpressId,showState = gModelSkill:GetBuffSkillData(buffId,showEff.refId,true)
						if buffExpressId then
							if LOG_INFO_ENABLED then
								printInfoN2("战斗",string.format("buff 技能表现 %s,%s,dead %s",buffExpressId,showState,isDead))
							end

							local curTime = self:GetTime()
							if (isDead and showState == ModelSkill.TYPE_SHOWSTATE_DIEAFTER) or
									(not isDead and showState == ModelSkill.TYPE_SHOWSTATE_DIEBEFORE) then

								local buffExpress = buffExpreCtrl:GetBuffExpre(buffExpressId)
								local para = {
									targetObj = tarHero,
									atkObj = atkHero,
									summonHero = summonHero,
									isSummonBuff = isSummonBuff,
									curTime = curTime,
									buffEffShowPos = buffEffShowPos,
								}
								buffExpress:StartRun(para)
								buffExpreCtrl:AddRunningExpre(buffExpress)
							end

							local doTime = curTime
							if showState == ModelSkill.TYPE_SHOWSTATE_TIGERUNFOLD then
								local buffExpress = buffExpreCtrl:GetBuffExpre(buffExpressId)
								local para = {
									targetObj = tarHero,
									atkObj = atkHero,
									summonHero = summonHero,
									isSummonBuff = isSummonBuff,
									curTime = doTime,
									buffEffShowPos = buffEffShowPos,
								}
								buffExpress:StartRun(para)
								buffExpreCtrl:AddRunningExpre(buffExpress)
								doTime = doTime + buffExpress:CalcSkillPlayTime()
							end


							local info = gModelSkill:GetBuffEffShowTimeInfo(buffId)
							if info then
								local buffEffShowTime,expressionId = info.buffEffShowTime,info.expressionId
								if expressionId and expressionId > 0 then
									expressionId = gModelSkill:GetSkinExpress(showEff.refId,expressionId,showState == ModelSkill.TYPE_SHOWSTATE_TIGERUNFOLD)
									if expressionId and expressionId > 0 then
										if buffEffShowTime == ModelSkill.TYPE_BUFFEFFSHOWTIME_REPLACE then
											local buffExpress = buffExpreCtrl:GetBuffExpre(expressionId)
											local para = {
												targetObj = tarHero,
												atkObj = atkHero,
												summonHero = summonHero,
												isSummonBuff = isSummonBuff,
												curTime = doTime,
												buffEffShowPos = buffEffShowPos,
												buffEffShowType = ModelSkill.TYPE_BUFFEFFSHOWTIME_REPLACE,
											}
											buffExpress:StartRun(para)
											buffExpreCtrl:SetSpecialExpre(tarHero,buffUniqueId,buffExpress)
											buffExpreCtrl:AddRunningExpre(buffExpress)
										end
									end
								end
							end
						end
					elseif etype == LFightConst.BUFF_TYPE_REMOVE then
						---buff 表现
						local showEff = tarHero:GetShowEffRef()
						local canShowEff = true
						local info = gModelSkill:GetBuffEffShowTimeInfo(buffId)
						local buffEffShowTime,expressionId = info.buffEffShowTime,info.expressionId
						if expressionId and expressionId > 0 then
							expressionId = gModelSkill:GetSkinExpress(showEff.refId,expressionId)
							if expressionId and expressionId > 0 then
								if buffEffShowTime == ModelSkill.TYPE_BUFFEFFSHOWTIME_REPLACE then
									tarHero:SetReplaceIdle(nil)
									buffExpreCtrl:RecycleSpecialExpre(tarHero,buffUniqueId)
									canShowEff = false
								end
							end
						end

						---buff 表现
						if canShowEff and not string.isempty(buffRefData.buffSkill) then
							local buffExprePara
							local buffExpressId,showState
							if buffRefData.specialShow == 1 then
								--- 可变身 且 buff 消散时表现
								buffExpressId,showState = gModelSkill:GetBuffSkillData(buffId,showEff.refId)
								if buffExpressId and buffExpressId > 0 then
									if showState == ModelSkill.TYPE_SHOWSTATE_DIEBEFORE and not tarHero:IsDead() then
										--- 非死亡状态下
										if LOG_INFO_ENABLED then
											printInfoN2("战斗","变身回正常状态~~~~")
										end
										buffExprePara = {
											targetObj = tarHero,
											atkObj = atkHero,
											curTime = self:GetTime(),
											buffEffShowPos = buffEffShowPos,
										}
									end
								end
							elseif hasHurtShields then
								buffExpressId,showState = gModelSkill:GetBuffSkillData(buffId,showEff.refId)
								if buffExpressId and buffExpressId > 0 then
									if LOG_INFO_ENABLED then
										printInfoN2("战斗","减伤buff破了")
									end
									buffExprePara = {
										targetObj = tarHero,
										atkObj = atkHero,
										curTime = self:GetTime(),
										buffEffShowPos = buffEffShowPos,
										targetObjs = cBuff103HurtList,
									}
								end
							else
								buffExpressId,showState = gModelSkill:GetBuffSkillData(buffId,showEff.refId)
								if buffExpressId and buffExpressId > 0 then
									buffExprePara = {
										targetObj = tarHero,
										atkObj = atkHero,
										curTime = self:GetTime(),
										buffEffShowPos = buffEffShowPos,
										buffId = buffId,
										targetObjs = {tarHero},
										isBombBuff = gModelBattle:CheckBuffEffectIsBomb(buffId),
									}
								end
							end
							if buffExprePara and buffExpressId and buffExpressId > 0 then
								---@type LFightBuffExpress
								local buffExpress = buffExpreCtrl:GetBuffExpre(buffExpressId)
								buffExpress:StartRun(buffExprePara)
								buffExpreCtrl:AddRunningExpre(buffExpress)
							end
						end

						if isHasBuffEffShow then
							if isFormationBuff then
								local side = tarHero:GetSide()
								local recordSideMap = self._rcdFormationBuffMap[side]
								if recordSideMap then
									local rcdBuffGroupMap = recordSideMap[buffEffShowType]
									if rcdBuffGroupMap then
										if LOG_INFO_ENABLED then
											printInfoNR("阵容 buff 移除 buffUniqueId：" .. rcdBuffGroupMap.buffUniqueId .. "，buffId：" .. buffId)
										end
										effectCtrl:DestroyEffect(rcdBuffGroupMap.effect)
										self._rcdFormationBuffMap[side][buffEffShowType] = nil
									end
								end
							end
							local recordBuffCreateMap = self._rcdBuffCreateMap
							if recordBuffCreateMap then
								local tarHeroId = tarHero:GetId()
								local recordIdMap = recordBuffCreateMap[tarHeroId]
								if recordIdMap and recordIdMap[buffId] then
									effectCtrl:DestroyEffect(recordIdMap[buffId].effect)
									recordBuffCreateMap[tarHeroId][buffId] = nil
								end
							end
						end
						self:InsertWaitRemove(buffUniqueId)
						tarHero:DoRemoveStatistics(buffUniqueId)
						tarHero:RefreshBuffBar()
					end

					if buffRefData.specialShow == 3 then
						local isRemove = etype == LFightConst.BUFF_TYPE_REMOVE
						local alpha = isRemove and 1 or 0.3
						tarHero:SetUnintelligibilityAlpha(alpha,isRemove)
					end
					isBuffUpdate = true
				end
			elseif effectType == LFightConst.ACTIONEFFECTENUM_SHIELD then --护盾表现效果
				local shield = {}
				shield.buffUniqueId = effect.buffUniqueId
				shield.shieldUniqueId = effect.shieldUniqueId
				if isLogOpen then
					local str = string.format("新增护盾的唯一ID：%s 护盾值 %s ",effect.shieldUniqueId,effect.hp)
					self:LogMsg(str)
				end
				shield.maxHP = effect.hp
				shield.curHP = effect.hp
				tarHero:AddShieldData(shield)
			elseif effectType == LFightConst.ACTIONEFFECTENUM_PSHIELD then --格挡盾表现效果
				local block = {}
				block.buffUniqueId = effect.buffUniqueId
				block.blockUniqueId = effect.blockUniqueId
				block.maxCount = effect.count
				block.curCount = effect.count
				tarHero:AddBlockData(block)
			elseif effectType == LFightConst.ACTIONEFFECTENUM_ANGER then --怒气表现效果
				local anger = {}
				anger.buffUniqueId = effect.buffUniqueId
				anger.angerValue = effect.angerValue
				if isLogOpen then
					local str = string.format("当前怒气：%s 层，怒气关联buff的唯一ID：%s ",anger.angerValue,effect.buffUniqueId)
					self:LogMsg(str)
				end
				tarHero:AddAngerData(anger)
			elseif effectType == LFightConst.ACTIONEFFECTENUM_SHIELDHURT then --护盾抵挡伤害表现效果
				local shield = {}
				shield.shieldUniqueId = effect.shieldUniqueId
				shield.hurt = - effect.hurt
				if isLogOpen then
					local str = string.format("护盾抵挡伤害：%s 护盾唯一ID：%s ",shield.hurt,effect.shieldUniqueId)
					self:LogMsg(str)
				end
				hudData = {
					targetHeroId = eId ,
					pos = pos+ offsetPos,
					time = time,
					hurt = effect.hurt,
					changeType = LFightConst.HURT_TYPE_SHIELD,
					playNum = playNum,
				}
				tarHero:UpdateShieldData(shield)
				--addOffset = true
			elseif effectType == LFightConst.ACTIONEFFECTENUM_POSITION then --站位变化
				local totalTime = (#(effect.wayIndexList or {}) +1) * 0.5
				local side = tarHero:GetActOn()
				local para = {
					side = side,
					effect = effect,
					duration =totalTime,
					endTime = time + totalTime,
					objCtrl = self._objCtrl,
				}
				self:StartPositionBuff(para)
			elseif effectType == LFightConst.ACTIONEFFECTENUM_SUMMON then
				self:AddSummonHero(effect)
			elseif effectType == LFightConst.ACTIONEFFECTENUM_ROUND then
				tarHero:UpdateBuffData(effect)
			elseif effectType == LFightConst.ACTIONEFFECTENUM_STATISTICS then
				tarHero:DoStatisticsUpdate(effect)
				tarHero:RefreshBuffBar()
			end

			if hudData and not hudData.changeType then
				printErrorN("nil hurt type")
			end

			if hudData then
				local target = hudData.targetHeroId
				local list = hudDataList[target]
				if not list then
					list = {}
					hudDataList[target] = list
				end

				table.insert(list,hudData)
			end
		end
	end

	for k,v in pairs(hudDataList) do
		local tarHero = self:GetHero(k)
		if tarHero then
			tarHero:ShowHud(v,doHurtTime,lBattleSkill)
		end
	end


	for k,v in pairs(heroRecord) do
		v:RefreshAfter()
	end

	if isBuffUpdate then
		FireEvent(EventNames.BUFF_UPDATE,true)
	end

end

--- 2024/6/3： 剔除无法表现的数据
function LFightUnit:RejectQueer(list)
	list = list or {}
	local resultList = {}
	for i,effect in ipairs(list) do
		local tarHero = self:GetHero(effect.eId)
		if not tarHero or not tarHero:IsOnGridObj() then
		else
			table.insert(resultList,effect)
		end
	end
	return resultList
end

--- 2024/7/10：判断是否护盾抵消伤害
function LFightUnit:CheckOffsetInjury(list)
	local hasShieldHurt = false
	local recordHurt = 0
	list = list or {}
	for i,effect in ipairs(list) do
		if effect.type == LFightConst.ACTIONEFFECTENUM_HURT then --伤害表现效果
			recordHurt = recordHurt + math.ceil(effect.hurt)
		elseif effect.type == LFightConst.ACTIONEFFECTENUM_SHIELDHURT then
			if not hasShieldHurt then hasShieldHurt = true end
		end
	end
	return hasShieldHurt and recordHurt < 1 or false
end


function LFightUnit:CollectBuffActMap(list)
	local buffActMap = {}
	local id2EffectMap = {}
	for i,effect in ipairs(list) do
		local aId = effect.aId
		local effectType = effect.type
		if effectType == LFightConst.ACTIONEFFECTENUM_HURT then
			local idEffects = id2EffectMap[aId]
			if not idEffects then
				idEffects = {}
				id2EffectMap[aId] = idEffects
			end
			table.insert(idEffects,effect)
		elseif effectType == LFightConst.ACTIONEFFECTENUM_BUFF then
			if id2EffectMap[aId] and effect.etype ~= LFightConst.BUFF_TYPE_REMOVE then
				local buffActList = buffActMap[aId]
				if not buffActList then
					buffActList = {}
					buffActMap[aId] = buffActList
				end
				buffActList[effect.buffId] = true
			end
		end
	end
	return buffActMap
end

---@param lBattleSkill LFightSkill
function LFightUnit:CollectBuff103HurtList(effectList,lBattleSkill)
	if not effectList or #effectList < 1 then return {},0 end

	local hurtHeroObjList = {}
	local hasHurtShields = false
	local hurtShieldBuffId
	local aId
	local atkHeroObj
	for i,effectStruct in ipairs(effectList) do
		local list = self:RejectQueer(effectStruct.list)
		for idx,effect in ipairs(list) do
			if hasHurtShields then
				if effect.type == LFightConst.ACTIONEFFECTENUM_HURT and effect.aId == aId then
					local tarHero = self:GetHero(effect.eId)
					if tarHero then
						table.insert(hurtHeroObjList,tarHero)
					end
				end
			else
				if effect.type == LFightConst.ACTIONEFFECTENUM_BUFF and
						effect.etype == LFightConst.BUFF_TYPE_REMOVE then
					if gModelBattle:CheckBuffHasHurtShields(effect.buffId) then
						local atkHero = self:GetHero(effect.aId)
						if atkHero and atkHero:IsOnGridObj() then
							aId = effect.aId
							atkHeroObj = atkHero
							hurtShieldBuffId = effect.buffId
							hasHurtShields = true
						end
					end
				end
			end
		end
	end
	local calcDelayTime = 0
	if lBattleSkill and hurtShieldBuffId and hurtShieldBuffId > 0 then
		if atkHeroObj then
			local showEff = atkHeroObj:GetShowEffRef()
			if showEff then
				local buffExpressId,showState = gModelSkill:GetBuffSkillData(hurtShieldBuffId,showEff.refId)
				if buffExpressId and buffExpressId > 0 and showState == ModelSkill.TYPE_SHOWSTATE_SHIELD then
					local skillShowEffEf = gModelSkill:GetSkillExpressionRef(buffExpressId)
					if skillShowEffEf then
						local hurtShieldsSds = gModelSkill:ParsePlayEff({},skillShowEffEf.playEff,showEff.refId)
						if hurtShieldsSds and #hurtShieldsSds > 0 then
							local tEffType
							for i,v in ipairs(hurtShieldsSds) do
								tEffType = v.effType
								--if tEffType ~= LSkillEffConst.PLAY_EFF_HIT_HUD and
								--		tEffType ~= LSkillEffConst.PLAY_EFF_HUD then
								--end

								calcDelayTime = calcDelayTime + v.delayTime
								--calcDelayTime = calcDelayTime + v.playTime + v.delayTime + v.dissipateTime
							end
						end
					end
				end
			end
		end
	end
	return hurtHeroObjList,calcDelayTime
end

function LFightUnit:CheckBombDelayTime(effectList)
	local delayTime = 0
	local buffId,effType,tarHero,showEff,buffExpressId
	---@type V_BuffRef
	local buffRefData
	for i,effectStruct in ipairs(effectList) do
		local list = self:RejectQueer(effectStruct.list)
		for idx,effect in ipairs(list) do
			if effect.type == LFightConst.ACTIONEFFECTENUM_BUFF and effect.etype == LFightConst.BUFF_TYPE_REMOVE then
				buffId = effect.buffId
				if gModelBattle:CheckBuffEffectIsBomb(buffId) then
					buffRefData = self:GetBuffRef(buffId)
					if buffRefData and not string.isempty(buffRefData.buffSkill) then
						tarHero = self:GetHero(effect.eId)
						showEff = tarHero and tarHero:GetShowEffRef()
						if showEff then
							buffExpressId = gModelSkill:GetBuffSkillData(buffId,showEff.refId)
							if buffExpressId and buffExpressId > 0 then
								---@type V_SkillExpressionRef
								local skillShowEffEf = gModelSkill:GetSkillExpressionRefByRefId(buffExpressId)
								if skillShowEffEf and not string.isempty(skillShowEffEf.playEff) then
									local playEffList = gModelSkill:ParsePlayEff({},skillShowEffEf.playEff,showEff.refId,false)
									for _i,v in ipairs(playEffList) do
										effType = v.effType
										if effType == LSkillEffConst.PLAY_EFF_HIT_HUD or effType == LSkillEffConst.PLAY_EFF_HUD then
											delayTime = delayTime + v.delayTime
										end
									end
								end
							end
						end
					end
				end
			end
		end
	end
	return delayTime
end

function LFightUnit:StartPositionBuff(para)

	local buffPosition = LFightBuffPosition:New(self)
	buffPosition:Start(para)
	if not self._buffPositionList then
		self._buffPositionList = {}
	end
	table.insert(self._buffPositionList,buffPosition)
end

function LFightUnit:OnBuffPositionRun(time)

	if not self._buffPositionList then
		return true
	end

	local cnt = #self._buffPositionList
	if cnt == 0 then
		return true
	end

	for k= cnt,1,-1 do
		local value = self._buffPositionList[k]
		value:OnRun(time)
		if value:IsEnd() then
			table.remove(self._buffPositionList,k)
		end
	end

	cnt = #self._buffPositionList

	return cnt == 0

end


function LFightUnit:ShowHurtCount(isHurt,num,playNum,time,side)
	self:ClearHurtCntList()

	local change = num
	local dataList = {}
	local sTime = time
	local totalRatio = 1
	local data =nil
	local totalHurt = 0
	local tempTime = sTime
	if playNum and #playNum>0 then

		for i, v in ipairs(playNum) do
			local showNum = math.floor(v[2]* change)
			data =
			{
				isHurt = isHurt,
				startTime = tempTime,
				showNum = showNum,
				side = side,
			}
			tempTime = sTime+ v[1]
			table.insert(dataList,data)
			totalRatio = totalRatio - v[2]
			totalHurt = totalHurt+ showNum
		end
	end

	local leftHurt = change - totalHurt
	if leftHurt >0 then
		data =
		{
			isHurt = isHurt,
			startTime = tempTime,
			showNum = leftHurt,
			side = side
		}
		table.insert(dataList,data)
	end

	self._hurtCntList = dataList
end

function LFightUnit:ClearHurtCntList()
	if self._hurtCntList and #self._hurtCntList>0 then
		local isHurt = nil
		local totalNum = 0
		local side = nil
		for k,v in ipairs(self._hurtCntList) do
			totalNum = totalNum+ v.showNum
			isHurt = v.isHurt
			side = v.side
		end

		self._hurtCounter:AddHurtCount(side,isHurt,totalNum)
		--FireEvent(EventNames.BATTLE_HURT_COUNT_UPDATE,isHurt,totalNum)
		if side and isHurt then
			self:AddShowHurtCnt(side,totalNum)
		end
		self._hurtCntList = nil
	end
end

function LFightUnit:UpdateHurtCount(time)
	if self._hurtCntList then
		local first = self._hurtCntList[1]
		if first then
			if first.startTime <= time then
				self._hurtCounter:AddHurtCount(first.side,first.isHurt,first.showNum)
				--FireEvent(EventNames.BATTLE_HURT_COUNT_UPDATE,first.isHurt,first.showNum)
				--printErrorN("cur show hurt cnt -----------------"..first.showNum)
				table.remove(self._hurtCntList,1)
				if first.side and first.isHurt then
					self:AddShowHurtCnt(first.side,first.showNum)
				end
			end
		end
	end
end



