function LFightUnit:RefreshTeamCurHpPercent(side)
	local objList = self:GetObjectCtrl():GetTeamBySide(side)
	local totalHp = 0
	for k,v in ipairs(objList) do
		totalHp = totalHp + (v:GetCurHP() or 0)
	end

	local teamMaxHP = nil
	local isLeft = false
	if side == LFightConst.ACTON_TEAM_A then
		teamMaxHP = self:GetTeamHPCountA()
		isLeft = true
	else
		teamMaxHP = self:GetTeamHPCountB()
	end

	local percent = 0
	if teamMaxHP>0 then
		percent = totalHp / teamMaxHP
	end

	self:RefreshBloodPercent(isLeft,percent)

	FireEvent(EventNames.BLOOD_UPDATE,isLeft,percent)
end

function LFightUnit:GetTeamBloodPercent(side)
	return self._bloodPercentRecord and self._bloodPercentRecord[side] or 1
