function LFightUnit:RefreshBloodPercent(isLeft,percent)
	if not self._bloodPercentRecord then
		self._bloodPercentRecord = {}
	end
	local side = isLeft and 1 or 2
	self._bloodPercentRecord[side] = percent


	--TODO refresh
	local teamIndex = self:GetCombatIndex()
	FireEvent(EventNames.REFRESH_BATTLE_TEAM_STATE,teamIndex)

end


function LFightUnit:InitTeamHP()
	self._teamHPCountA = 0
	self._teamHPCountB = 0
	self._teamHPA = 0
	self._teamHPB = 0

	for i,heroData in ipairs(self._formationA) do
		self._teamHPCountA = self._teamHPCountA + heroData._maxHP
	end
	for i,heroData in ipairs(self._formationA) do
		self._teamHPA = self._teamHPA + heroData._hp
	end

	for i,heroData in ipairs(self._formationB) do
		self._teamHPCountB = self._teamHPCountB + heroData._maxHP
	end
	for i,heroData in ipairs(self._formationB) do
		self._teamHPB = self._teamHPB + heroData._hp
	end

	FireEvent(EventNames.BLOOD_INIT,true)
end





