---切换到后台
function LFightUnit:ChangeToBackground()


	if self._isBackgroundPlay then
		return
	end


	if self:IsDestroy() then
		return
	end


	self._isStartPlay = false
	self._bWaitBattleStart = false

	self:StopDelayResetScaleTimer()
	self._isShowingLastEff = false

	if not self:IsBattleInit() then
		self:InitBattle()
	end
	self._isBackgroundPlay = true
	if #self._curSkill > 0 then
		for i, v in ipairs(self._curSkill) do
			v:Destroy()
		end
		self._curSkill = {}
	end


	self._buffExpreCtrl:ClearBuffExpre()

	self:SetWaitNextSkillShow(true)


	self:ClearPreloadSkill()

	self._objCtrl:ClearAllObject()
	self._effCtrl:ClearAllEffect()
	self._decoraCtrl:ClearAllEffect()

	if self._treaObjCtrl then
		self._treaObjCtrl:ClearAllObj()
	end

	self._mapFormationGridA = {}
	self._mapFormationGridB = {}

	-- self._artifactAPos = nil
	-- self._artifactBPos = nil

	if not self._waitTime then
		self._waitTime = 0
		self:SetWaitNextSkillShow(true)
	end
	--self._waitTime = 0
	--self:SetWaitNextSkillShow(true)

	if self._delatBackToBattleHandle then
		LxTimer.DelayTimeStop(self._delatBackToBattleHandle)
		self._delatBackToBattleHandle = nil
	end

	gLFightManager:ResetTimeScale()
	--gModelBattle:SetBattleUnitFightSpeed(0)
end

