function  LFightUnit:OnBattleEnd()
	if self._isEndExecute then
		printInfoN("is end executed")
		return
	end

	if self._isWaitAllDead then
		printInfoN("is wait all dead")
		return
	end

	if self._isShowingLastEff then
		printInfoN("is Showing LastEff")
		return
	end

	self._isEndExecute = true

	local logCtrl = self:GetLogCtrl()
	if logCtrl:IsLogOpen() then
		logCtrl:LogHpFinal(self._formationA,self._formationB)
		logCtrl:SaveHpLog()
	end

	self:ClearUIOnEnd()

	local teamIndex = self:GetCombatIndex()
	FireEvent(EventNames.REFRESH_BATTLE_TEAM_STATE,teamIndex)

	gLFightManager:OnBattlePlayEnd(self)

end

