function LFightUnit:CheckCanRelive(heroId)

	if self:CheckSkillRecord(heroId,self._reliveSkillRecord) then
		return true
	end

	local lifeState = self._battleReportData:GetLifeState()
	if self:CheckSkillRecord(heroId,lifeState) then
		return true
	end


	return false
end

function LFightUnit:CheckSkillRecord(heroId,record)
	if not record then
		return false
	end
	local side = self:GetHeroSide(heroId)
	local tempSide = nil
	for k,v in pairs(record) do
		if v[1] then    ---可复活他人
			local heroData = self:GetHeroData(k)
			if not heroData then
				if LOG_INFO_ENABLED then
					print("miss heroData "..k)
				end
			else
				if not heroData:IsDead() then
					tempSide = self:GetHeroSide(k)
					if tempSide == side then
						return true
					end
				end
			end

		elseif v[2] then  ---只能复活自己
			if heroId == k then
				return true
			end
		end
	end

	return false
end


