function LFightUnit:CompareIndexInfo(a,b)
	if a.roundIndex< b.roundIndex then
		return false
	elseif a.roundIndex> b.roundIndex then
		return true
	end
	if a.boutIndex< b.boutIndex then
		return false
	elseif a.boutIndex> b.boutIndex then
		return true
	end
	if a.actionIndex< b.actionIndex then
		return false
	elseif a.actionIndex> b.actionIndex then
		return true
	end
	--if a.effectIndex> b.effectIndex then
	--	return true
	--end
	return false
end

