function LFightUnit:ChaseTo(timePast)
	local speed = self:GetSpeed()
	self._chaseEndTime = timePast/4 * speed  + self:GetTime()
	if self._isBattleStart then
		gLFightManager:PlayBattleTimeScale(4)
		self._isChasing = true
	end

end

function LFightUnit:UpdateChase(time)
	if self._chaseEndTime then
		if time > self._chaseEndTime then
			self:StopChase()
		else
			if self._isBattleStart and not self._isChasing then
				gLFightManager:PlayBattleTimeScale(4)
				self._isChasing = true
			end
		end
	end
end

function LFightUnit:StopChase()
	self._chaseEndTime = nil
	self._isChasing = false
	self:ResetSpeed()
end

