function LFightUnit:ShowWaitStartEff()
	local effectData =
	{
		effectKey = "waitStartEff",
		resName = "fx_zhandoujinchangtuzi",
		root = self:GetEffectRootTrans(),
		loadedCall = function(effect)
			if effect:IsVisible() then
				self:LoopWaitEff(effect)
			end
		end,
	}

	self._decoraCtrl:CreateEffect(effectData)
end

function LFightUnit:LoopWaitEff(effect)
	local seqCom = self:GetSeqCom()
	local tran = effect:GetDisplayTrans()
	if CS.IsValidObject(tran) then
		tran.localPosition = Vector3.New(-0.25,0.51,0)
	end
	local seq = seqCom:CreateSeq("loopRestart")
	seq:AppendCallback(function ()
		effect:RestartFx()
	end)
	seq:AppendInterval(5)
	seq:SetLoops(-1)
	seq:PlayForward()
end

function LFightUnit:HideWaitEff()
	local seqCom = self:GetSeqCom()
	seqCom:DeleteSeq("loopRestart")
	local info = self._decoraCtrl:FindEffectInfoByKey("waitStartEff")
	if info and info.effect then
		info.effect:SetVisible(false)
	end
end

