---@return LFightObjectData
function LFightUnit:AddSummonHeroData(effect)
	if not self._buffUIdToId then
		self._buffUIdToId = {}
	end
	local buffUId = effect.buffUniqueId
	local heroId = self._buffUIdToId[buffUId]
	if heroId then
		return self._mapFormationData[heroId]
	end
	local heroId = effect.hero.id
	local side = effect.belong == 1 and LFightConst.ACTON_TEAM_A or LFightConst.ACTON_TEAM_B

	local callHero = self:GetHeroData(effect.aId)
	local skin = callHero:GetSkinId()

	local heroData = LFightObjectData:New()
	-- 【C宠物系统】删掉宠物系统相关
	-- if effect.hero.unitType == 3 then
	-- 	heroData:InitPetData(effect.hero,side,skin)
	-- else
		heroData:InitSummonHeroData(effect.hero,side,skin)
	-- end

	self._buffUIdToId[buffUId] = heroId
	self._mapFormationData[heroId] = heroData

	return heroData
end

function LFightUnit:AddSummonHero(effect)
	local heroData = self:AddSummonHeroData(effect)

	local side = heroData:GetActOn()
	local index = heroData:GetIndex()
	local id = heroData:GetId()
	local parentTrans = self._objectRootTrans
	local objCtrl = self:GetObjectCtrl()
	local gripMap = side == LFightConst.ACTON_TEAM_A and self._mapFormationGridA or self._mapFormationGridB
	local grid = gripMap[index]
	local onLoadEnd = function()
		local battleObj = objCtrl:GetObjectById(id)
		battleObj:ShowSummonBirth()
	end
	local obj = objCtrl:MakeObject(heroData, parentTrans, grid, onLoadEnd)
	if obj then
		objCtrl:AddObject(obj)
		obj:StartLoadDp()
	end
end

function LFightUnit:InsertWaitRemove(buffUId)
	if not self._buffUIdToId then return end

	local heroId = self._buffUIdToId[buffUId]
	if not heroId then return end

	if not self._waitRemoveHero then
		self._waitRemoveHero = {}
	end

	table.insert(self._waitRemoveHero,{heroId = heroId,buffUId = buffUId})
end

function LFightUnit:RemoveSummonHero(removeData)

	local buffUId = removeData.buffUId
	self._buffUIdToId[buffUId] = nil
	local heroId = removeData.heroId
	self._mapFormationData[heroId] = nil
	local objCtrl = self:GetObjectCtrl()
	objCtrl:DestroyObjById(heroId)
end

---@return LFightObject|nil
function LFightUnit:GetSummonHero(buffUniqueId)
	local heroId = self._buffUIdToId[buffUniqueId]
	if not heroId then return end

	local objCtrl = self:GetObjectCtrl()
	if not objCtrl then return end

	return objCtrl:GetObjectById(heroId)
end

function LFightUnit:CheckRemoveSummon()
	if not self._waitRemoveHero then
		return
	end

	for k,v in ipairs(self._waitRemoveHero) do
		self:RemoveSummonHero(v)
	end
end



function LFightUnit:HideAllBlood()
	local objCtrl = self:GetObjectCtrl()
	local objList = objCtrl:GetObjectList() or {}
	for k,v in ipairs(objList) do
		if v:IsNormalObj() then
			v:SetHideBloodKey("drawing")
		end
	end
end

function LFightUnit:RecoverBloodShow()
	local objCtrl = self:GetObjectCtrl()
	local objList = objCtrl:GetObjectList() or {}
	for k,v in ipairs(objList) do
		if v:IsNormalObj() then
			v:ReleaseHideKey("drawing")
		end
	end
end

function LFightUnit:GetShowInfo()
	return self._battleReportData:GetShowInfo()
end


---@return boolean  是否92类型的
function LFightUnit:CheckBuffEffectIs92(buffId)
	local buffRef = self:GetBuffRef(buffId)
	if not buffRef then return false end
	local buffEffectId = buffRef.effectId
	if not buffEffectId or buffEffectId == "" then return false end
	local buffEffectIds = string.split(buffEffectId,"|")
	for i,v in ipairs(buffEffectIds) do
		v = tonumber(v)
		if gModelBattle:CheckBuffEffectIs92(v) then
			return true
		end
	end
	return false
end

function LFightUnit:ResetBuffEffect(id,show)
	local recordBuffCreateMap = self._rcdBuffCreateMap
	if not recordBuffCreateMap then return end

	local idMap = recordBuffCreateMap[id]
	if not idMap then return end

	for k,v in pairs(idMap) do
		---@type LFightEffect
		local effect = v.effect
		if effect and not effect:IsDestroy() then
			effect:SetVisible(show)
		end
	end
end

-----------------------------------------------------------------
function LFightUnit:Destroy()

	if LOG_INFO_ENABLED then
		print("LFightUnit:Destroy()")
	end

	if self._bDestroyed then return end

	self:ClearSeqCom()

	local effectCtrl = self:GetEffectCtrl()
	for showSide,v in pairs(self._rcdFormationBuffMap) do
		for buffEffShowType,v1 in pairs(v) do
			effectCtrl:DestroyEffect(v1.effect)
		end
	end

	if not self._isBackgroundPlay then
		if gLGameAudio then
			--gLGameAudio:CloseMapMusic()
		end
		gLFightManager:ResetTimeScale()
	end

	self:StopRun()
	self:StopDelayResetScaleTimer()

	if self._curSkill and #self._curSkill > 0 then
		for i, v in ipairs(self._curSkill) do
			v:Destroy()
		end
		self._curSkill = {}
	end

	self:ClearPreloadSkill()

	if self._objCtrl then
		self._objCtrl:Destroy()
	end
	if self._effCtrl then
		self._effCtrl:Destroy()
	end

	if self._treaObjCtrl then
		self._treaObjCtrl:Destroy()
	end

	if self._deadEffect then
		self._deadEffect:Destroy()
	end

	if self._deadWarnEff then
		self._deadWarnEff:Destroy()
	end

	if self._buffExpreCtrl then
		self._buffExpreCtrl:Destroy()
	end

	if self._decoraCtrl then
		self._decoraCtrl:Destroy()
	end


	table.removeall(self)

	self._isEndExecute = true
	self._bDestroyed = true
end


return LFightUnit